import type { InterviewQuestion } from './realInterviewQuestions';

export const sets: Record<string, InterviewQuestion[]> = {
  'java-interview-questions': [
    { q: 'How does the JVM manage memory, and what changed you should know in Java 25 LTS?', short: 'Heap + stack + metaspace, managed by a garbage collector; Java 25 continues generational ZGC and virtual-thread maturity.', strong: 'Objects live on the heap (young/old generations), method frames on the stack, class metadata in metaspace. Collectors like G1 (default) and ZGC/Shenandoah trade throughput for pause time. Java 25 LTS ships mature virtual threads (Project Loom) and generational ZGC, so high-concurrency services scale without tuning huge thread pools.', followUp: 'When would you pick ZGC over G1?', checking: 'Do you understand memory regions and modern collectors, not just "the GC frees memory".', mistake: 'Saying the JVM has no stack, or that finalizers are how you free memory.' },
    { q: 'What is the difference between == and equals(), and how does hashCode() fit in?', short: '== compares references (or primitives); equals() compares logical value; hashCode() must be consistent with equals().', strong: 'For objects, == checks identity; equals() checks logical equality if overridden. If you override equals(), you must override hashCode() so equal objects share a hash bucket — otherwise HashMap/HashSet break. The contract: equal objects → equal hash codes (not vice versa).', followUp: 'What breaks if hashCode() is inconsistent with equals()?', checking: 'Understanding of identity vs equality and the collections contract.', mistake: 'Overriding equals() but not hashCode().' },
    { q: 'Explain the Java Collections hierarchy and when you would use each core structure.', short: 'List (order), Set (uniqueness), Map (key→value), Queue/Deque (ends); pick by access pattern.', strong: 'ArrayList for indexed access, LinkedList rarely (poor cache locality), HashMap/HashSet for O(1) lookup, TreeMap/TreeSet for sorted order, ArrayDeque for stacks/queues, ConcurrentHashMap for concurrent access. Choose by the operations you do most and thread-safety needs.', followUp: 'ArrayList vs LinkedList for a queue?', checking: 'Practical data-structure judgment, not memorized definitions.', mistake: 'Defaulting to LinkedList or Vector out of habit.' },
    { q: 'How do virtual threads change concurrency in modern Java?', short: 'Lightweight threads scheduled by the JVM; blocking is cheap, so you can have millions.', strong: 'Virtual threads (stable since Java 21, matured in 25) let you write simple blocking code that scales like async. The JVM parks a virtual thread on blocking I/O without pinning an OS thread, so thread-per-request models scale massively. Avoid pooling virtual threads and be careful with synchronized blocks that pin carriers.', followUp: 'What still pins a carrier thread?', checking: 'Awareness of current concurrency direction, not just old thread pools.', mistake: 'Treating virtual threads as a drop-in for CPU-bound parallelism.' },
    { q: 'What are checked vs unchecked exceptions, and how should you use them?', short: 'Checked = recoverable, must handle/declare; unchecked = programming errors, runtime.', strong: 'Checked exceptions (extends Exception) force handling — use for recoverable conditions callers can act on. Unchecked (RuntimeException) signal bugs like NPE or illegal args. Modern practice leans toward unchecked for most app errors to avoid boilerplate, wrapping causes and failing fast with clear messages.', followUp: 'When would you create a custom exception?', checking: 'Judgment about error design, not dogma.', mistake: 'Catching Exception broadly and swallowing it.' },
    { q: 'How does the Stream API work, and what is lazy evaluation?', short: 'A pipeline of intermediate (lazy) + terminal (eager) operations over a source.', strong: 'Streams build a pipeline: intermediate ops (map, filter) are lazy and only run when a terminal op (collect, reduce) executes. This enables fusion and short-circuiting (findFirst, limit). Use them for readable transformations, but avoid them in hot loops where the overhead matters, and never reuse a consumed stream.', followUp: 'What is a stateful vs stateless intermediate operation?', checking: 'Understanding laziness and pipeline mechanics.', mistake: 'Assuming streams are always faster than loops.' },
    { q: 'Explain the volatile keyword and the Java Memory Model briefly.', short: 'volatile guarantees visibility and ordering for a field, not atomicity of compound actions.', strong: 'volatile ensures reads/writes go to main memory and establishes happens-before ordering, so one thread sees another’s write. It does not make count++ atomic — that needs AtomicInteger or synchronization. The JMM defines when writes by one thread become visible to others.', followUp: 'Why is count++ not thread-safe even if count is volatile?', checking: 'Real concurrency understanding vs keyword-dropping.', mistake: 'Thinking volatile provides mutual exclusion.' },
    { q: 'What is dependency injection and why does it matter in Java apps?', short: 'Providing a class its dependencies from outside rather than constructing them itself.', strong: 'DI inverts control: instead of new-ing collaborators, a class receives them (constructor injection preferred). This decouples code, eases testing with mocks, and lets frameworks like Spring manage lifecycles. It underpins testable, modular architectures.', followUp: 'Constructor vs field injection — which and why?', checking: 'Design maturity and testability awareness.', mistake: 'Confusing DI the pattern with Spring the framework.' },
    { q: 'How would you debug a memory leak in a Java service?', short: 'Reproduce, capture a heap dump, analyze dominators, find retained references.', strong: 'Watch heap and GC logs for a rising baseline after GC. Capture a heap dump (jmap/JFR) and open it in a tool like Eclipse MAT to find dominator trees and what retains large object sets — often static collections, unbounded caches, or listeners never removed. Fix the reference and add a bound or cleanup.', followUp: 'What common patterns cause leaks in long-running apps?', checking: 'Practical production debugging skill.', mistake: 'Guessing at code instead of taking a heap dump.' },
    { q: 'What are records and sealed classes, and when are they useful?', short: 'Records = immutable data carriers; sealed = restricted inheritance hierarchies.', strong: 'Records auto-generate constructor, accessors, equals/hashCode/toString for immutable data — great for DTOs and value objects. Sealed classes/interfaces restrict which types can extend them, enabling exhaustive pattern matching in switch. Together they make modeling domains safer and more concise.', followUp: 'How do sealed types improve switch pattern matching?', checking: 'Familiarity with modern Java, not just Java 8.', mistake: 'Never having used features past Java 8.' },
    { q: 'Explain the difference between synchronized and a ReentrantLock.', short: 'Both provide mutual exclusion; ReentrantLock adds features like tryLock, fairness, interruptibility.', strong: 'synchronized is simple and JVM-managed with automatic release. ReentrantLock is explicit (must unlock in finally) but supports tryLock with timeout, fairness policies, condition variables, and interruptible acquisition. Use synchronized by default; reach for ReentrantLock when you need those capabilities.', followUp: 'Why must you unlock in a finally block?', checking: 'Correct concurrency primitives usage.', mistake: 'Forgetting to release the lock, causing deadlock.' },
    { q: 'How do you design a REST API in Spring Boot for scalability?', short: 'Stateless endpoints, proper status codes, pagination, caching, and async where needed.', strong: 'Keep endpoints stateless so you can scale horizontally, use correct HTTP verbs/status codes, paginate large collections, add caching (ETags, cache headers), validate input, and offload slow work to async/queues. Add observability (metrics, tracing) so you can find bottlenecks under load.', followUp: 'How would you handle a slow downstream dependency?', checking: 'System-level thinking beyond a single controller.', mistake: 'Returning unbounded lists with no pagination.' },
  ],
  'python-interview-questions': [
    { q: 'What is the difference between a list, tuple, and set in Python?', short: 'List = mutable ordered; tuple = immutable ordered; set = mutable unordered unique.', strong: 'Lists are mutable and ordered (dynamic arrays). Tuples are immutable, hashable if their contents are, and useful as dict keys or fixed records. Sets store unique, unhashable-free items with O(1) membership. Choose by mutability, ordering, and lookup needs.', followUp: 'Why can a tuple be a dict key but a list cannot?', checking: 'Understanding of mutability and hashability.', mistake: 'Thinking tuples are just "read-only lists" with no other purpose.' },
    { q: 'Explain the GIL and its impact on concurrency.', short: 'The GIL lets only one thread execute Python bytecode at a time; it limits CPU-bound threading.', strong: 'CPython’s Global Interpreter Lock serializes bytecode execution, so threads don’t give true parallelism for CPU-bound work — use multiprocessing or native extensions for that. Threads still help I/O-bound work. Python 3.13+ ships an experimental free-threaded (no-GIL) build, and 3.14 continues that work.', followUp: 'How do you achieve parallelism for CPU-bound tasks today?', checking: 'Current, accurate understanding of the GIL and 3.14 direction.', mistake: 'Claiming threads give parallel CPU speedups in standard CPython.' },
    { q: 'What are decorators and how do they work?', short: 'Callables that wrap a function to add behavior, using @syntax.', strong: 'A decorator takes a function and returns a new function, letting you add cross-cutting behavior (logging, caching, auth) without changing the wrapped code. @decorator is sugar for f = decorator(f). Use functools.wraps to preserve metadata. functools.lru_cache is a common built-in decorator.', followUp: 'How would you write a decorator that takes arguments?', checking: 'Understanding of first-class functions and closures.', mistake: 'Forgetting functools.wraps and losing the function name/docstring.' },
    { q: 'How does Python manage memory and garbage collection?', short: 'Reference counting plus a cyclic garbage collector.', strong: 'CPython frees objects when their reference count hits zero, and a generational cyclic collector handles reference cycles. Understanding this helps avoid leaks from lingering references (globals, caches, closures) and explains why del just decrements a count.', followUp: 'What creates a reference cycle and how is it collected?', checking: 'Depth beyond "Python handles memory for you".', mistake: 'Believing del immediately frees memory.' },
    { q: 'What is the difference between deep copy and shallow copy?', short: 'Shallow copies the container; deep copies nested objects recursively.', strong: 'copy.copy() creates a new outer object but shares nested references; copy.deepcopy() recursively duplicates everything. Mutating a nested list in a shallow copy affects the original — a classic bug source with nested data structures.', followUp: 'When would a shallow copy cause a subtle bug?', checking: 'Awareness of reference semantics.', mistake: 'Assuming assignment or slicing fully clones nested data.' },
    { q: 'Explain generators and the yield keyword.', short: 'Generators produce values lazily, one at a time, preserving state between calls.', strong: 'A function with yield returns a generator that computes values on demand, using constant memory for large or infinite sequences. Great for streaming pipelines and large-file processing. yield from delegates to a sub-generator.', followUp: 'How do generators help with a huge file you can’t load into memory?', checking: 'Understanding of lazy evaluation and memory efficiency.', mistake: 'Building a full list when a generator would do.' },
    { q: 'What are *args and **kwargs?', short: 'Collect extra positional and keyword arguments respectively.', strong: '*args gathers extra positional args into a tuple; **kwargs gathers extra keyword args into a dict. They enable flexible APIs and forwarding arguments to wrapped functions (common in decorators). Order: positional, *args, keyword-only, **kwargs.', followUp: 'How do you forward all arguments to another function?', checking: 'Comfort with flexible function signatures.', mistake: 'Confusing the two or misordering parameters.' },
    { q: 'How do you handle async I/O in Python?', short: 'asyncio with async/await for cooperative, single-threaded concurrency.', strong: 'async def defines coroutines; await yields control on I/O so the event loop runs other tasks. It scales I/O-bound workloads (APIs, DB, network) without threads. Use asyncio.gather for concurrency, and avoid blocking calls inside the loop.', followUp: 'What happens if you call a blocking function inside an async coroutine?', checking: 'Understanding of the event loop model.', mistake: 'Mixing blocking calls into async code and stalling the loop.' },
    { q: 'What is the difference between @staticmethod, @classmethod, and instance methods?', short: 'Instance methods take self; classmethod takes cls; staticmethod takes neither.', strong: 'Instance methods operate on an object (self). classmethods receive the class (cls) and are used for alternative constructors or class-level state. staticmethods are namespaced utility functions with no implicit first arg. Choose by what state you need.', followUp: 'When is a classmethod the right choice over a staticmethod?', checking: 'OOP understanding in Python.', mistake: 'Using staticmethod where a classmethod constructor fits.' },
    { q: 'How would you optimize a slow Python data-processing script?', short: 'Profile first, then vectorize, use better data structures, or move hot paths to C/NumPy.', strong: 'Measure with cProfile to find real hot spots. Replace Python loops with vectorized NumPy/pandas ops, use sets/dicts for lookups, stream with generators, cache with lru_cache, and consider multiprocessing or native extensions for CPU-bound sections. Don’t optimize blind.', followUp: 'Why profile before optimizing?', checking: 'Disciplined performance engineering.', mistake: 'Micro-optimizing before profiling.' },
  ],
  'react-interview-questions': [
    { q: 'How do React hooks work, and what rules must you follow?', short: 'Hooks add state/effects to function components; call them at the top level, unconditionally.', strong: 'Hooks like useState/useEffect let function components hold state and side effects. React tracks them by call order, so you must call them unconditionally at the top level, not in loops or conditions. Custom hooks compose built-ins to share logic. This is current through React 19.2.', followUp: 'Why does calling a hook conditionally break React?', checking: 'Understanding of the hooks model, not just syntax.', mistake: 'Calling hooks inside conditions or loops.' },
    { q: 'Explain the virtual DOM and reconciliation.', short: 'React diffs a virtual tree against the previous one and updates only what changed.', strong: 'React builds a lightweight virtual representation of the UI; on state change it re-renders, diffs against the prior tree, and applies the minimal real-DOM updates. Keys help it match list items efficiently. React 19’s compiler can auto-memoize to reduce needless re-renders.', followUp: 'Why are stable keys important in lists?', checking: 'Grasp of rendering performance fundamentals.', mistake: 'Using array index as key for dynamic lists.' },
    { q: 'What is the difference between useMemo, useCallback, and React.memo?', short: 'Memoize a value, a function, and a component respectively.', strong: 'useMemo caches a computed value; useCallback caches a function reference; React.memo skips re-rendering a component when props are unchanged. Use them to prevent expensive recomputation or breaking referential equality — but don’t over-apply; React 19’s compiler reduces the need.', followUp: 'When does over-using useMemo hurt?', checking: 'Judgment about performance, not cargo-culting.', mistake: 'Wrapping everything in useMemo without measuring.' },
    { q: 'How do you manage side effects with useEffect?', short: 'Run effects after render; declare dependencies; clean up to avoid leaks.', strong: 'useEffect runs after paint for data fetching, subscriptions, etc. The dependency array controls when it re-runs; return a cleanup function to cancel subscriptions or timers. Missing deps cause stale closures; over-broad deps cause loops. For data fetching, prefer libraries or Suspense patterns.', followUp: 'What causes an infinite re-render loop with useEffect?', checking: 'Correct effect and dependency reasoning.', mistake: 'Omitting dependencies or missing cleanup.' },
    { q: 'What are React Server Components and why do they matter?', short: 'Components rendered on the server, shipping less JS to the client.', strong: 'RSCs render on the server, can access data directly, and send serialized output — reducing client bundle size and improving performance. Client components (marked "use client") handle interactivity. This split, mainstream in React 19 + frameworks like Next.js 16, is a major shift in how apps are structured.', followUp: 'What can’t you do inside a Server Component?', checking: 'Awareness of current React architecture.', mistake: 'Assuming everything must be a client component.' },
    { q: 'How does state management scale beyond useState?', short: 'Lift state, use context for shared state, or a library for complex global state.', strong: 'Start with local useState, lift shared state to a common parent, use Context for low-frequency global values (theme, auth), and reach for a store (Redux Toolkit, Zustand) or server-state libraries (TanStack Query) for complex or server-derived state. Avoid putting everything in one giant context.', followUp: 'Why is Context a poor fit for high-frequency updates?', checking: 'Architectural judgment.', mistake: 'Using Context for rapidly changing state and causing re-render storms.' },
    { q: 'What causes unnecessary re-renders and how do you fix them?', short: 'New references, unstable props, or context changes; fix with memoization and structure.', strong: 'Re-renders happen when state/props/context change. Common culprits: inline objects/functions creating new references, over-broad context, and lifting state too high. Fix with useCallback/useMemo, React.memo, splitting context, or colocating state. React 19’s compiler auto-optimizes many cases.', followUp: 'How would you diagnose which component re-renders too often?', checking: 'Practical performance debugging.', mistake: 'Optimizing without the React DevTools profiler.' },
    { q: 'How do you handle forms and validation in React?', short: 'Controlled inputs or form libraries; validate on change/submit with clear errors.', strong: 'Controlled components bind input value to state; for complex forms use libraries (React Hook Form) to reduce re-renders and handle validation, errors and submission cleanly. React 19 adds form actions and useActionState for progressive, server-friendly forms.', followUp: 'Controlled vs uncontrolled inputs — trade-offs?', checking: 'Real-world form handling.', mistake: 'Re-rendering the whole form on every keystroke unnecessarily.' },
    { q: 'How would you improve the performance of a large React list?', short: 'Virtualize, memoize rows, stable keys, and avoid heavy work in render.', strong: 'Render only visible rows with virtualization (react-window/virtual), give stable keys, memoize row components, keep render pure and cheap, and paginate or lazy-load data. Move expensive computation out of render or into useMemo.', followUp: 'Why does rendering 10,000 rows at once hurt?', checking: 'Understanding of rendering cost at scale.', mistake: 'Rendering huge lists without virtualization.' },
    { q: 'What is the difference between client-side and server-side rendering in React apps?', short: 'CSR renders in the browser; SSR/SSG render HTML ahead of time for speed and SEO.', strong: 'CSR ships JS that builds the UI in-browser — flexible but slower first paint and weaker SEO. SSR renders HTML per request; SSG pre-renders at build. Frameworks like Next.js 16 mix these per route, with RSC reducing shipped JS. Choose by SEO, freshness, and performance needs.', followUp: 'When would you pick SSG over SSR?', checking: 'Rendering strategy judgment.', mistake: 'Treating an SEO-critical site as pure CSR.' },
  ],
  'devops-interview-questions': [
    { q: 'How would you design a CI/CD pipeline for a microservices app?', short: 'Build → test → scan → containerize → deploy per service, with gates and rollbacks.', strong: 'Each service gets its own pipeline: build, unit/integration tests, security and image scanning, container build, then progressive deploy (canary/blue-green) with automated rollback on failed health checks. Use trunk-based development, artifact versioning, and environment promotion. Keep pipelines fast so they stay trusted.', followUp: 'How do you keep 50 service pipelines maintainable?', checking: 'End-to-end delivery design, not just "we use Jenkins".', mistake: 'One giant pipeline for all services with no isolation.' },
    { q: 'What is Infrastructure as Code and why does it matter?', short: 'Declaring infra in version-controlled code for repeatable, reviewable provisioning.', strong: 'IaC (Terraform, etc.) defines infrastructure declaratively so it is versioned, peer-reviewed, and reproducible across environments. It eliminates snowflake servers, enables drift detection, and makes disaster recovery a re-apply. State management and modules keep it maintainable.', followUp: 'How do you handle Terraform state safely in a team?', checking: 'IaC discipline and collaboration.', mistake: 'Manual console changes that drift from code.' },
    { q: 'Explain blue-green vs canary deployments.', short: 'Blue-green swaps whole environments; canary shifts a small % of traffic first.', strong: 'Blue-green keeps two identical environments and switches traffic all at once (fast rollback by switching back). Canary routes a small slice of traffic to the new version, watches metrics, then ramps up. Canary limits blast radius; blue-green gives instant full cutover. Choose by risk tolerance and infra cost.', followUp: 'How do you decide when a canary is healthy enough to promote?', checking: 'Release-safety understanding.', mistake: 'Big-bang deploys with no rollback plan.' },
    { q: 'How do you monitor and observe a production system?', short: 'Metrics, logs, and traces, with SLOs and actionable alerts.', strong: 'The three pillars — metrics (Prometheus), logs (centralized), traces (OpenTelemetry) — plus dashboards (Grafana) and alerts tied to SLOs, not noise. Alert on symptoms users feel, keep runbooks, and reduce alert fatigue. Good observability turns "it is slow" into a root cause fast.', followUp: 'What makes an alert good vs noisy?', checking: 'Operational maturity.', mistake: 'Alerting on every metric and drowning on-call.' },
    { q: 'How do you handle secrets in a pipeline and at runtime?', short: 'Never in code; use a secrets manager and inject at deploy/runtime.', strong: 'Store secrets in a manager (Vault, cloud secret stores), inject via environment or mounted volumes at runtime, rotate regularly, and scope least-privilege access. Keep them out of git, logs, and images. Scan for accidental commits in CI.', followUp: 'What do you do if a secret leaks into git history?', checking: 'Security hygiene.', mistake: 'Hardcoding secrets in env files committed to the repo.' },
    { q: 'What is the difference between horizontal and vertical scaling?', short: 'Horizontal adds instances; vertical adds resources to one instance.', strong: 'Vertical scaling gives a node more CPU/RAM — simple but capped and a single point of failure. Horizontal scaling adds more nodes behind a load balancer — resilient and elastic but needs statelessness and coordination. Cloud-native systems favor horizontal with autoscaling.', followUp: 'What must be true of an app to scale horizontally?', checking: 'Scalability fundamentals.', mistake: 'Assuming you can just add nodes to a stateful app.' },
    { q: 'How would you reduce a slow Docker image build and large image size?', short: 'Layer caching, multi-stage builds, small base images, and .dockerignore.', strong: 'Order Dockerfile steps so rarely-changing layers cache; use multi-stage builds to ship only artifacts; pick slim/distroless bases; and add .dockerignore to shrink context. This cuts build time and attack surface. Pin versions for reproducibility.', followUp: 'Why does step order matter for caching?', checking: 'Container efficiency.', mistake: 'Copying the whole context early and busting the cache.' },
    { q: 'Describe how you would respond to a production incident.', short: 'Detect, mitigate, communicate, resolve, then blameless postmortem.', strong: 'Acknowledge the alert, assess blast radius, mitigate first (rollback, scale, feature flag) before root-causing, communicate status to stakeholders, then fix and verify. Afterward run a blameless postmortem with action items so it does not recur. Calm process beats heroics.', followUp: 'Why mitigate before finding the root cause?', checking: 'Incident-response discipline.', mistake: 'Debugging root cause while users stay down.' },
  ],
  'aws-interview-questions': [
    { q: 'How do you design a highly available architecture on AWS?', short: 'Multi-AZ, load balancing, autoscaling, managed data stores, no single points of failure.', strong: 'Spread compute across Availability Zones behind an ELB, use Auto Scaling groups, put data in multi-AZ RDS/Aurora or DynamoDB, and front with Route 53 health checks. Add caching (CloudFront/ElastiCache) and decouple with SQS/SNS. Design so any one AZ or instance can fail without downtime.', followUp: 'How would you extend this to multi-region?', checking: 'Well-Architected reliability thinking.', mistake: 'Single-AZ deployments called "highly available".' },
    { q: 'Explain IAM roles vs users vs policies.', short: 'Users = long-term creds; roles = assumable temporary creds; policies = permissions.', strong: 'IAM users hold long-term credentials; roles grant temporary credentials assumed by services or federated identities (preferred, no static keys); policies (JSON) define allowed/denied actions. Best practice: least privilege, roles over users for workloads, and no root usage.', followUp: 'Why prefer roles over access keys for EC2 workloads?', checking: 'Security model understanding.', mistake: 'Baking access keys into instances or code.' },
    { q: 'When would you use S3 vs EBS vs EFS?', short: 'S3 = object storage; EBS = block volume for one instance; EFS = shared file system.', strong: 'S3 for durable object storage (assets, backups, data lakes) via API; EBS for low-latency block storage attached to a single EC2 instance; EFS for a shared POSIX file system across many instances. Choose by access pattern, sharing, and latency needs.', followUp: 'Which fits a shared upload directory across many app servers?', checking: 'Storage selection judgment.', mistake: 'Using EBS where shared access (EFS/S3) is needed.' },
    { q: 'How do Lambda and serverless change architecture?', short: 'Event-driven, auto-scaling functions with no servers to manage; pay per use.', strong: 'Lambda runs code in response to events, scaling automatically and billing per invocation. It suits event processing, APIs (with API Gateway), and glue logic. Watch cold starts, execution limits, and statelessness; use Step Functions for orchestration. It shifts ops burden to design and observability.', followUp: 'What are the trade-offs vs always-on containers?', checking: 'Serverless design awareness.', mistake: 'Using Lambda for long-running, heavy, stateful workloads.' },
    { q: 'How would you optimize AWS costs without hurting reliability?', short: 'Right-size, autoscale, savings plans, storage tiers, and kill idle resources.', strong: 'Right-size from real metrics, autoscale to demand, buy Savings Plans/Reserved for steady load, use Spot for fault-tolerant work, move cold data to cheaper S3 tiers, and clean up unattached EBS/idle resources. Tag and monitor with Cost Explorer/budgets.', followUp: 'Where would Spot instances be risky?', checking: 'Cost-vs-reliability judgment.', mistake: 'Over-provisioning "just in case" and never reviewing spend.' },
    { q: 'Explain VPC basics: subnets, route tables, and security groups.', short: 'A VPC is your private network; subnets segment it; SGs are stateful instance firewalls.', strong: 'A VPC is an isolated network; public/private subnets segment it by route table (public routes to an internet gateway, private via NAT). Security groups are stateful, instance-level allow rules; NACLs are stateless subnet-level rules. Good design keeps databases in private subnets.', followUp: 'Why put your database in a private subnet?', checking: 'Networking fundamentals.', mistake: 'Exposing databases in public subnets.' },
    { q: 'How do you build a decoupled, event-driven system on AWS?', short: 'Use SQS/SNS/EventBridge between producers and consumers.', strong: 'Producers publish to SNS/EventBridge; consumers process from SQS queues with retries and dead-letter queues for failures. This decouples components, absorbs spikes, and improves resilience. Idempotency and DLQ handling are essential for correctness.', followUp: 'Why do you need a dead-letter queue?', checking: 'Distributed-systems reliability.', mistake: 'Synchronous tight coupling that fails under load.' },
  ],
  'genai-interview-questions': [
    { q: 'When should you use RAG vs fine-tuning an LLM?', short: 'RAG for fresh/proprietary knowledge; fine-tuning for behavior, format, or domain style.', strong: 'RAG injects relevant retrieved context at inference — best for up-to-date, proprietary, or large knowledge bases without retraining. Fine-tuning changes model behavior, tone, or output format and suits narrow, stable tasks. They combine well: fine-tune for style, RAG for facts. Start with RAG; fine-tune when prompt+retrieval is not enough.', followUp: 'What are the cost and maintenance trade-offs of each?', checking: 'Practical GenAI architecture judgment.', mistake: 'Fine-tuning to add knowledge that changes daily.' },
    { q: 'How do you design a production RAG pipeline?', short: 'Chunk, embed, store in a vector DB, retrieve, re-rank, then generate with grounding.', strong: 'Ingest and chunk documents thoughtfully, embed them, store in a vector DB (with metadata for filtering), retrieve top-k by similarity (often hybrid with keyword), re-rank, then prompt the LLM with retrieved context and citations. Add evaluation and guardrails. Chunking and retrieval quality drive most of the outcome.', followUp: 'What do you do when retrieval returns irrelevant chunks?', checking: 'End-to-end RAG understanding.', mistake: 'Dumping whole documents into the prompt with no retrieval strategy.' },
    { q: 'How do you evaluate an LLM application?', short: 'Task-specific metrics, groundedness checks, and human or LLM-as-judge review.', strong: 'Define what "good" means per task: correctness, groundedness (no hallucination), relevance, tone, safety. Use offline eval sets, automated metrics, LLM-as-judge with care, and human review for high-stakes cases. Track regressions across prompt/model changes like tests.', followUp: 'How do you catch hallucinations systematically?', checking: 'Evaluation rigor, not vibes.', mistake: 'Shipping with only anecdotal "it looks good" testing.' },
    { q: 'What is prompt engineering and what techniques actually help?', short: 'Structuring input for reliable output: clear instructions, examples, and constraints.', strong: 'Effective techniques: clear role/task instructions, few-shot examples, explicit output format/schema, step-by-step reasoning where useful, and constraints/guardrails. Keep prompts versioned and tested. For complex tasks, decompose into steps or tools rather than one mega-prompt.', followUp: 'When does chain-of-thought help vs hurt?', checking: 'Hands-on prompting maturity.', mistake: 'Treating prompt tweaks as untracked magic.' },
    { q: 'How do you reduce hallucinations in an LLM system?', short: 'Ground with retrieval, constrain output, cite sources, and verify.', strong: 'Ground answers in retrieved, authoritative context; instruct the model to say "I do not know" when context is missing; require citations; constrain to a schema; and add a verification pass or guardrail for high-stakes outputs. Lower temperature for factual tasks. No single trick — layered defenses.', followUp: 'How would you make the model refuse when it lacks context?', checking: 'Reliability engineering for LLMs.', mistake: 'Assuming a bigger model alone eliminates hallucination.' },
    { q: 'What is an embedding and how is it used in GenAI?', short: 'A vector representation of meaning used for similarity search.', strong: 'Embeddings map text (or images) to vectors where semantic similarity ≈ vector proximity. They power retrieval, clustering, deduplication, and classification. In RAG, you embed documents and the query, then find nearest neighbors in a vector DB. Choice of embedding model and dimensionality affects quality and cost.', followUp: 'Why might two embedding models give different retrieval quality?', checking: 'Core GenAI plumbing understanding.', mistake: 'Confusing embeddings with the generative model itself.' },
    { q: 'How would you build an agentic AI workflow reliably?', short: 'Bound tools, add planning + guardrails, and make steps observable and idempotent.', strong: 'Give the agent a clear goal, a bounded set of well-described tools, and a planning loop with limits (max steps, budgets). Add validation between steps, human-in-the-loop for risky actions, retries with idempotency, and full tracing. Reliability and cost control matter more than cleverness in production.', followUp: 'How do you stop an agent from looping or overspending?', checking: 'Awareness of agentic reliability, a 2026 hot topic.', mistake: 'Giving an agent unbounded tools and no step/cost limits.' },
  ],
  'forward-deployed-engineer-interview-questions': [
    { q: 'What does a Forward Deployed Engineer do, and how is it different from a regular software engineer?', short: 'An FDE embeds with customers to deploy, integrate and customize the product in their real environment.', strong: 'An FDE sits between engineering and the customer: they deploy the product into the client systems, build integrations and data pipelines, prototype solutions to the customer problems, and feed learnings back to the core product. Unlike a pure SWE, success is measured by customer outcomes, and the job demands strong communication alongside coding.', followUp: 'When do you push a fix into the core product vs solve it just for one customer?', checking: 'Whether you understand the customer-facing, outcome-driven nature of the role.', mistake: 'Describing it as a pure coding role with no customer or delivery dimension.' },
    { q: 'Walk me through deploying our platform into a customer with messy, siloed data.', short: 'Discover the data, map it, build ingestion/cleaning pipelines, validate, then integrate incrementally.', strong: 'Start by understanding the customer systems and data sources, then design ingestion that cleans and normalizes messy inputs, with validation and observability. Deliver incrementally — a small end-to-end slice first to prove value — and keep stakeholders looped in. Plan for schema drift and access constraints from day one.', followUp: 'How do you handle a source that changes format without warning?', checking: 'Practical data-integration judgment under real-world messiness.', mistake: 'Assuming clean, well-documented data and a big-bang cutover.' },
    { q: 'How do you balance shipping a fast prototype for a customer vs building something maintainable?', short: 'Prototype to prove value fast, then harden what works; be explicit about the trade-off.', strong: 'FDEs move fast to show value, but flag prototype code as such and plan the path to production. Prove the outcome with a lightweight build, get customer buy-in, then invest in reliability, tests and generalization for what proves valuable. Communicate the trade-off so the customer is not surprised by a later hardening phase.', followUp: 'When would you refuse to ship a prototype to production?', checking: 'Pragmatism balanced with engineering responsibility.', mistake: 'Either over-engineering the first demo or shipping throwaway code as if it were production.' },
    { q: 'Design an integration between our product and a customer existing systems.', short: 'Clarify systems and data, choose API/event/batch, handle auth, errors, idempotency and monitoring.', strong: 'Scope the source and target systems and the data contract, pick the right pattern (REST/webhooks/event stream/batch) for latency and volume, handle authentication and least-privilege access, design for retries, idempotency and partial failure, and add monitoring so breakages surface fast. Keep it incremental and observable.', followUp: 'How do you guarantee you do not double-process records?', checking: 'Integration and distributed-systems fundamentals.', mistake: 'A happy-path design with no error handling or idempotency.' },
    { q: 'A customer deployment is failing in production and you do not have full access. How do you debug?', short: 'Work through the customer: gather logs/metrics, reproduce safely, isolate, and fix with their help.', strong: 'Since you cannot always touch the environment directly, guide the customer to collect logs, metrics and repro steps, form a hypothesis, and narrow it down methodically. Communicate status calmly, mitigate first (rollback/flag) if severity is high, then root-cause. Document so it does not recur. Trust and clear comms matter as much as the fix.', followUp: 'How do you handle it when the customer team is the bottleneck?', checking: 'Real-world incident handling with limited access and a client in the loop.', mistake: 'Freezing without access, or making risky changes blind.' },
    { q: 'How would you build a RAG or LLM feature on top of a customer data?', short: 'Ingest and chunk their data, embed, retrieve, ground the LLM, and evaluate for correctness.', strong: 'Ingest and chunk the customer documents/data with metadata, embed and store in a vector DB, retrieve relevant context at query time (often hybrid), and prompt the LLM with grounding and citations. Add evaluation for hallucination and relevance, plus guardrails. Respect the customer data privacy and access boundaries throughout.', followUp: 'How do you keep the customer sensitive data private in an LLM feature?', checking: 'Current GenAI/RAG skills plus data-governance awareness.', mistake: 'Sending sensitive customer data to a model with no privacy consideration.' },
    { q: 'How do you manage stakeholders when technical reality and business expectations differ?', short: 'Communicate early, translate trade-offs into business terms, and propose options.', strong: 'Surface the gap early rather than late. Explain the trade-off in the stakeholder language (cost, time, risk), propose a small set of options with recommendations, and align on a path. Under-promise and over-deliver, and keep a written record so expectations stay shared.', followUp: 'How do you say no to a customer request without losing the relationship?', checking: 'The client-facing, communication half of the FDE role.', mistake: 'Silently over-committing, then missing the expectation.' },
    { q: 'Coding: given a messy CSV/JSON export, load and clean it for downstream use. How do you approach it?', short: 'Inspect, define a schema, handle types/nulls/dupes, validate, and load with error reporting.', strong: 'Inspect a sample first, define the target schema, then parse robustly — coercing types, handling missing and malformed values, deduplicating, and normalizing. Validate against the schema, report rejected rows rather than silently dropping them, and make the pipeline re-runnable and idempotent. Real FDE data work lives here.', followUp: 'What do you do with rows that fail validation?', checking: 'Hands-on data-wrangling ability, not just theory.', mistake: 'Silently dropping bad rows or assuming clean input.' },
    { q: 'When do you hard-code something for one customer vs generalize it into the product?', short: 'Hard-code to prove value fast; generalize when a pattern repeats across customers.', strong: 'Early, a customer-specific solution is fine to prove value and move fast. Once you see the same need across multiple customers, push it into the core product so it is maintained centrally. Track these patterns and feed them to product — turning field learnings into product features is a core FDE contribution.', followUp: 'How do you decide it is worth the product team time?', checking: 'Product sense and the FDE-to-product feedback loop.', mistake: 'Either hard-coding everything forever, or over-generalizing from a single case.' },
    { q: 'Why do you want an FDE role rather than a core engineering role?', short: 'You want customer impact, variety, and to both build and deliver outcomes.', strong: 'A strong answer connects to enjoying customer impact, fast-moving variety, and owning outcomes end-to-end — building real solutions and seeing them used. It shows comfort with ambiguity and communication, not just coding. Tie it to concrete examples where you delivered for a stakeholder, not just shipped code.', followUp: 'Tell me about a time you turned a vague customer problem into a working solution.', checking: 'Genuine fit for a customer-facing, delivery-focused role.', mistake: 'Answering as if it is just another backend job.' },
  ],
  'kubernetes-interview-questions': [
    { q: 'Explain the core Kubernetes architecture.', short: 'A control plane (API server, scheduler, controller-manager, etcd) manages worker nodes running kubelet and pods.', strong: 'The control plane exposes the API server (the single source of truth backed by etcd), the scheduler assigns pods to nodes, and controllers reconcile desired vs actual state. Worker nodes run the kubelet (which manages pods), a container runtime, and kube-proxy for networking. Everything is declarative and reconciled continuously — current to Kubernetes 1.36.', followUp: 'What happens when etcd is unavailable?', checking: 'Whether you understand the declarative, reconciliation-based model.', mistake: 'Describing it as an imperative system that runs commands once.' },
    { q: 'What is the difference between a Deployment, StatefulSet and DaemonSet?', short: 'Deployment for stateless replicas, StatefulSet for stable identity/storage, DaemonSet for one pod per node.', strong: 'Deployments manage interchangeable stateless pods with rolling updates. StatefulSets give stable network identities and persistent volumes for ordered, stateful apps (databases, queues). DaemonSets run exactly one pod per node for agents like logging or monitoring. Choose by whether pods need identity, ordering or per-node placement.', followUp: 'Why can’t you use a Deployment for a clustered database?', checking: 'Workload-selection judgment.', mistake: 'Using a Deployment for stateful workloads that need stable identity.' },
    { q: 'How does a Service expose pods, and what are the Service types?', short: 'A Service load-balances to pods via selectors; types are ClusterIP, NodePort, LoadBalancer and ExternalName.', strong: 'A Service provides a stable virtual IP and DNS name and routes to matching pods by label selector, decoupling clients from pod churn. ClusterIP is internal-only, NodePort exposes a port on every node, LoadBalancer provisions a cloud LB, and ExternalName maps to an external DNS name. Ingress sits above Services for HTTP routing.', followUp: 'How does traffic actually reach a pod behind a ClusterIP?', checking: 'Understanding of Kubernetes networking.', mistake: 'Confusing Ingress with a Service type.' },
    { q: 'How do you debug a pod stuck in CrashLoopBackOff?', short: 'Check logs, describe the pod, inspect events, resources and probes, then fix the root cause.', strong: 'Run kubectl describe pod for events, kubectl logs (and --previous) for the crash reason, and check resource limits, failing liveness probes, missing config/secrets, or a bad image/command. CrashLoopBackOff means the container keeps exiting; the fix depends on the actual exit cause, so read the logs and events first.', followUp: 'How would a too-aggressive liveness probe cause this?', checking: 'Practical troubleshooting method.', mistake: 'Guessing at fixes without reading logs and events.' },
    { q: 'Explain requests and limits, and how they affect scheduling and QoS.', short: 'Requests reserve resources for scheduling; limits cap usage; together they set the pod’s QoS class.', strong: 'Requests are what the scheduler uses to place pods and are guaranteed; limits cap CPU (throttled) and memory (OOM-killed if exceeded). Pods with requests==limits get Guaranteed QoS, partial get Burstable, none get BestEffort — which affects eviction order under pressure. Set both thoughtfully to balance density and reliability.', followUp: 'What happens when a container exceeds its memory limit?', checking: 'Resource-management understanding.', mistake: 'Setting no requests/limits, causing noisy-neighbor and eviction issues.' },
    { q: 'How do rolling updates and rollbacks work in a Deployment?', short: 'The Deployment gradually replaces old ReplicaSet pods with new ones and can roll back to a prior revision.', strong: 'A Deployment creates a new ReplicaSet and scales it up while scaling the old one down, honoring maxSurge/maxUnavailable and readiness probes so traffic only hits ready pods. If something breaks, kubectl rollout undo returns to a previous revision. Health probes are what make this safe.', followUp: 'Why are readiness probes essential during a rollout?', checking: 'Safe-deployment knowledge.', mistake: 'Rolling out without readiness probes, sending traffic to unready pods.' },
    { q: 'How do you manage configuration and secrets in Kubernetes?', short: 'ConfigMaps for non-sensitive config, Secrets for sensitive data, injected as env vars or mounted files.', strong: 'ConfigMaps hold non-sensitive configuration; Secrets hold sensitive values (base64-encoded, ideally encrypted at rest and backed by an external secrets manager). Both mount as env vars or files. Keep them out of images, scope access with RBAC, and rotate secrets. For real security, integrate a KMS or external secrets operator.', followUp: 'Are Kubernetes Secrets encrypted by default?', checking: 'Config/security awareness.', mistake: 'Assuming Secrets are strongly encrypted out of the box.' },
    { q: 'What is an Ingress and how does it differ from a LoadBalancer Service?', short: 'Ingress does host/path-based HTTP routing via a controller; a LoadBalancer Service exposes one service at L4.', strong: 'An Ingress resource defines HTTP(S) routing rules (hosts, paths, TLS) and needs an Ingress controller (NGINX, cloud) to implement them — letting many services share one entry point. A LoadBalancer Service provisions a dedicated L4 load balancer per service. Ingress is more cost-efficient and flexible for HTTP; gateways/Gateway API are the emerging evolution.', followUp: 'When would you still use a LoadBalancer Service directly?', checking: 'Traffic-routing design.', mistake: 'Provisioning a cloud LB per service instead of using Ingress.' },
  ],
  'spring-boot-interview-questions': [
    { q: 'What problem does Spring Boot solve over plain Spring?', short: 'Auto-configuration, starters and an embedded server remove boilerplate and speed up development.', strong: 'Spring Boot layers convention over configuration on top of Spring: auto-configuration wires sensible defaults from the classpath, starter dependencies bundle what you need, an embedded server (Tomcat/Netty) makes apps self-contained, and Actuator adds production endpoints. You focus on business logic instead of XML and manual wiring — current to Spring Boot 4.1 on Spring Framework 7.', followUp: 'How does auto-configuration decide what to configure?', checking: 'Understanding of what Boot actually adds.', mistake: 'Thinking Spring Boot is a different framework rather than Spring plus conventions.' },
    { q: 'How does Spring dependency injection work, and which injection type is preferred?', short: 'The container manages beans and injects dependencies; constructor injection is preferred.', strong: 'Spring’s IoC container creates and wires beans by type (and qualifier). Constructor injection is preferred because it makes dependencies explicit, supports immutability and final fields, and fails fast if a dependency is missing — unlike field injection, which hides dependencies and complicates testing.', followUp: 'Why is field injection discouraged?', checking: 'DI best-practice awareness.', mistake: 'Defaulting to @Autowired field injection everywhere.' },
    { q: 'Explain the bean lifecycle and common bean scopes.', short: 'Beans are created, wired, initialized (@PostConstruct), used, then destroyed; scopes include singleton and prototype.', strong: 'The container instantiates a bean, injects dependencies, runs initialization callbacks (@PostConstruct/InitializingBean), serves it, and runs destruction callbacks on shutdown. Default scope is singleton (one per context); prototype creates a new instance per request; web scopes include request and session. Most beans are stateless singletons.', followUp: 'What’s the risk of putting mutable state in a singleton bean?', checking: 'Lifecycle and concurrency awareness.', mistake: 'Storing per-request mutable state in a singleton.' },
    { q: 'How do you build a REST API in Spring Boot?', short: '@RestController with mapping annotations, DTOs, validation, and proper status codes.', strong: 'Use @RestController and @GetMapping/@PostMapping etc., accept and return DTOs (not entities), validate input with @Valid/Bean Validation, handle errors centrally with @ControllerAdvice, and return correct HTTP status codes. Add pagination for collections and document with OpenAPI. Keep controllers thin and push logic into services.', followUp: 'Why return DTOs instead of JPA entities?', checking: 'API design maturity.', mistake: 'Exposing entities directly, leaking the persistence model.' },
    { q: 'How does exception handling work in Spring Boot REST APIs?', short: 'Centralize with @ControllerAdvice/@ExceptionHandler mapping exceptions to responses.', strong: 'A @RestControllerAdvice class with @ExceptionHandler methods maps exceptions to consistent error responses and status codes, keeping controllers clean. Combine with a standard error body and validation-error handling. This centralizes cross-cutting error behavior instead of try/catch in every controller.', followUp: 'How do you return a 404 vs 400 vs 500 appropriately?', checking: 'Error-handling design.', mistake: 'Catching and swallowing exceptions in each controller.' },
    { q: 'How do you manage transactions with @Transactional?', short: '@Transactional wraps a method in a transaction with configurable propagation and rollback rules.', strong: '@Transactional starts/commits a transaction around a method, rolling back on runtime exceptions by default. Understand propagation (REQUIRED, REQUIRES_NEW), that it works via proxies (self-invocation bypasses it), and that checked exceptions don’t roll back unless configured. Keep transactions short and at the service layer.', followUp: 'Why doesn’t @Transactional work when a method calls another method in the same class?', checking: 'Understanding of proxy-based AOP.', mistake: 'Expecting self-invocation to be transactional.' },
    { q: 'How do you secure a Spring Boot application?', short: 'Spring Security for authentication/authorization, with JWT/OAuth2 for stateless APIs.', strong: 'Spring Security provides a filter chain for authentication and authorization. For APIs, use stateless JWT or OAuth2/OIDC resource-server support, method-level security for fine-grained rules, HTTPS, and CSRF handling appropriate to the client. Configure least-privilege roles and validate tokens properly.', followUp: 'Why disable CSRF for a stateless JWT API but not for a session app?', checking: 'Security understanding.', mistake: 'Copy-pasting security config without understanding stateless vs session.' },
    { q: 'What does Spring Boot Actuator provide for production?', short: 'Health, metrics, info and other operational endpoints for monitoring and management.', strong: 'Actuator exposes production endpoints — health (with readiness/liveness groups for Kubernetes), metrics (via Micrometer to Prometheus), info, env, loggers and more. It makes apps observable and manageable out of the box. Secure the endpoints and expose only what you need.', followUp: 'How do Actuator health groups map to Kubernetes probes?', checking: 'Production/operability awareness.', mistake: 'Exposing all Actuator endpoints publicly.' },
  ],
  'dotnet-interview-questions': [
    { q: 'What is the difference between .NET Framework, .NET Core and modern .NET?', short: 'Modern .NET (current: .NET 10) is the unified, cross-platform successor to the Windows-only .NET Framework.', strong: '.NET Framework is Windows-only and legacy. .NET Core unified and cross-platformed the runtime; from .NET 5 onward it is just “.NET”, with .NET 10 the current LTS. Modern .NET is open-source, cross-platform, high-performance and the target for all new work. Legacy apps may still run on .NET Framework 4.8.', followUp: 'Why would you still target .NET Framework today?', checking: 'Awareness of the current .NET landscape.', mistake: 'Treating .NET Core and .NET Framework as interchangeable.' },
    { q: 'Explain value types vs reference types in C#.', short: 'Value types hold data directly (stack/inline); reference types hold a reference to heap data.', strong: 'Value types (structs, int, bool, enums) contain their data and are copied by value; reference types (classes, strings, arrays) hold a reference, so copies share the same object. This affects equality, mutation and performance. Understand boxing (value → object) and its cost, and prefer structs for small, immutable data.', followUp: 'What is boxing and when does it hurt performance?', checking: 'Core language and memory understanding.', mistake: 'Assuming structs behave like classes on assignment.' },
    { q: 'How does async/await work in C#?', short: 'await suspends a method without blocking the thread, resuming on completion via a state machine.', strong: 'async/await lets you write asynchronous code sequentially; the compiler builds a state machine that releases the thread on await and resumes when the awaited Task completes. It scales I/O-bound work by not blocking threads. Avoid async void (except event handlers), avoid .Result/.Wait() (deadlocks), and flow cancellation tokens.', followUp: 'Why can .Result cause a deadlock?', checking: 'Correct async understanding.', mistake: 'Blocking on async code with .Result/.Wait().' },
    { q: 'What is dependency injection in ASP.NET Core?', short: 'A built-in IoC container registers services with lifetimes and injects them via constructors.', strong: 'ASP.NET Core has a built-in DI container. You register services in the composition root with a lifetime — Singleton, Scoped (per request) or Transient — and they are injected via constructors. This decouples components and eases testing. Choosing the right lifetime (e.g., Scoped for DbContext) is critical.', followUp: 'What goes wrong if you inject a Scoped service into a Singleton?', checking: 'DI and lifetime understanding.', mistake: 'Captive dependencies — a Singleton holding a Scoped service.' },
    { q: 'How does Entity Framework Core work, and what are common pitfalls?', short: 'An ORM mapping classes to tables with change tracking; watch N+1 queries and tracking overhead.', strong: 'EF Core maps entities to tables, tracks changes and generates SQL. Common pitfalls: N+1 queries (fix with Include/projection), loading more than needed (use AsNoTracking for reads and Select projections), and lazy loading surprises. Understand LINQ-to-SQL translation and inspect the generated queries.', followUp: 'How do you avoid the N+1 problem?', checking: 'Practical data-access skill.', mistake: 'Ignoring the generated SQL and loading whole graphs.' },
    { q: 'What is the middleware pipeline in ASP.NET Core?', short: 'An ordered chain of components that each handle the request/response and call the next.', strong: 'ASP.NET Core processes requests through an ordered middleware pipeline configured in the app startup — each middleware can act on the request, short-circuit, or pass to the next via next(). Order matters (e.g., authentication before authorization, exception handling first). Common middleware: routing, auth, CORS, static files.', followUp: 'Why must UseAuthentication come before UseAuthorization?', checking: 'Request-pipeline understanding.', mistake: 'Adding middleware in the wrong order.' },
    { q: 'Explain garbage collection and IDisposable in .NET.', short: 'The GC reclaims managed memory; IDisposable releases unmanaged resources deterministically.', strong: 'The generational GC frees managed objects automatically. Unmanaged resources (files, sockets, DB connections) are not GC-timed, so implement IDisposable and use using/using-declarations to release them deterministically. Understand the dispose pattern and avoid finalizers unless wrapping unmanaged handles.', followUp: 'Why prefer using over relying on a finalizer?', checking: 'Resource-management understanding.', mistake: 'Leaking unmanaged resources by not disposing.' },
    { q: 'How would you build a scalable Web API in ASP.NET Core?', short: 'Stateless controllers, DTOs, async I/O, caching, pagination and proper status codes.', strong: 'Keep controllers thin and stateless, use DTOs and model validation, make I/O async, add response caching/ETags, paginate collections, return correct status codes, and centralize errors. Add observability (logging, metrics, health checks) and scale horizontally behind a load balancer. Consider minimal APIs for lightweight endpoints.', followUp: 'How would you handle a slow downstream dependency?', checking: 'API architecture maturity.', mistake: 'Synchronous, stateful controllers that do not scale.' },
  ],
  'sql-interview-questions': [
    { q: 'Explain the different types of SQL JOINs.', short: 'INNER, LEFT/RIGHT OUTER, FULL OUTER and CROSS control which matched/unmatched rows are returned.', strong: 'INNER JOIN returns only matching rows; LEFT JOIN returns all left rows plus matches (NULLs otherwise); RIGHT is the mirror; FULL OUTER returns all rows from both; CROSS produces the Cartesian product. Choosing correctly — and handling the NULLs from outer joins — is where candidates often slip.', followUp: 'How do NULLs from a LEFT JOIN affect a WHERE filter on the right table?', checking: 'Core querying skill.', mistake: 'Filtering the right table in WHERE and accidentally turning a LEFT JOIN into an INNER JOIN.' },
    { q: 'What is the difference between WHERE and HAVING?', short: 'WHERE filters rows before grouping; HAVING filters groups after aggregation.', strong: 'WHERE applies to individual rows before GROUP BY, so it cannot use aggregate functions. HAVING filters the aggregated groups afterward and can use aggregates like COUNT/SUM. Use WHERE to reduce rows early (better performance) and HAVING only for conditions on aggregates.', followUp: 'Why is filtering in WHERE usually more efficient than HAVING?', checking: 'Understanding of query execution order.', mistake: 'Putting non-aggregate filters in HAVING and hurting performance.' },
    { q: 'How do database indexes work and when should you add one?', short: 'Indexes (usually B-trees) speed lookups/sorts at the cost of write overhead and storage.', strong: 'An index is a sorted structure (typically a B-tree) that lets the engine find rows without scanning the whole table — great for WHERE, JOIN and ORDER BY columns. But every index adds write cost and storage. Index selective, frequently-filtered columns; consider composite and covering indexes; avoid over-indexing.', followUp: 'What is a covering index?', checking: 'Performance-tuning knowledge.', mistake: 'Indexing everything, slowing writes and wasting space.' },
    { q: 'What are window functions and when are they useful?', short: 'They compute across a set of rows related to the current row without collapsing them.', strong: 'Window functions (ROW_NUMBER, RANK, LAG/LEAD, SUM OVER) compute values over a partition/order without grouping rows away — ideal for running totals, rankings, deduplication and period-over-period comparisons. They are more expressive and often faster than self-joins or subqueries for these tasks.', followUp: 'How would you get the latest row per group using a window function?', checking: 'Modern SQL proficiency.', mistake: 'Reaching for correlated subqueries where a window function is cleaner.' },
    { q: 'Explain ACID properties and transaction isolation levels.', short: 'ACID = Atomicity, Consistency, Isolation, Durability; isolation levels trade consistency for concurrency.', strong: 'ACID guarantees reliable transactions. Isolation levels (Read Uncommitted → Read Committed → Repeatable Read → Serializable) control anomalies like dirty reads, non-repeatable reads and phantoms, trading concurrency for consistency. Pick the lowest level that prevents the anomalies your workload cannot tolerate.', followUp: 'Which anomaly does Repeatable Read still allow?', checking: 'Transaction fundamentals.', mistake: 'Not knowing the anomalies each level permits.' },
    { q: 'How would you find and fix a slow query?', short: 'Read the execution plan, look for scans/spills, then add indexes or rewrite the query.', strong: 'Capture the query, read its execution plan for table scans, expensive sorts, key lookups or bad estimates, and check statistics. Fixes include adding/adjusting indexes, rewriting to be sargable (avoid functions on indexed columns), reducing returned columns, and updating statistics. Measure before and after.', followUp: 'What makes a predicate non-sargable?', checking: 'Practical tuning method.', mistake: 'Guessing at indexes without reading the execution plan.' },
    { q: 'What is normalization, and when would you denormalize?', short: 'Normalization removes redundancy; denormalization re-introduces it for read performance.', strong: 'Normalization (1NF–3NF) organizes data to eliminate redundancy and update anomalies. Denormalization deliberately duplicates data to speed reads (fewer joins), common in reporting/analytics and read-heavy systems — at the cost of write complexity and consistency risk. Choose based on read/write patterns.', followUp: 'What are the risks of denormalized data?', checking: 'Data-modeling judgment.', mistake: 'Treating normalization as always-right regardless of workload.' },
    { q: 'What is the difference between DELETE, TRUNCATE and DROP?', short: 'DELETE removes rows (logged, filtered); TRUNCATE removes all rows fast; DROP removes the table.', strong: 'DELETE removes selected rows with WHERE, is fully logged and can be rolled back and fire triggers. TRUNCATE removes all rows quickly with minimal logging and resets identity, but is less granular. DROP removes the table structure entirely. Choose by whether you need filtering, speed or full removal.', followUp: 'Can you roll back a TRUNCATE?', checking: 'Command semantics.', mistake: 'Assuming TRUNCATE and DELETE behave identically.' },
  ],
  'azure-interview-questions': [
    { q: 'How do you design a highly available application on Azure?', short: 'Use Availability Zones, load balancing, autoscale, and geo-redundant managed data services.', strong: 'Spread compute across Availability Zones behind Azure Load Balancer/Application Gateway, use VM Scale Sets or AKS with autoscaling, and choose zone- or geo-redundant managed data (Azure SQL, Cosmos DB). Add Front Door/Traffic Manager for multi-region, and design for failure of any single zone. Define your RTO/RPO first.', followUp: 'How would you extend this to multi-region active-active?', checking: 'Cloud reliability design.', mistake: 'Single-region, single-zone deployments called highly available.' },
    { q: 'Explain Azure AD (Entra ID) roles, RBAC and managed identities.', short: 'Entra ID handles identity; RBAC grants scoped permissions; managed identities remove secrets.', strong: 'Microsoft Entra ID (formerly Azure AD) is the identity provider. Azure RBAC assigns roles (Owner/Contributor/Reader/custom) scoped to management group, subscription, resource group or resource — least privilege. Managed identities give Azure resources an identity to call other services without storing credentials.', followUp: 'Why prefer a managed identity over a service principal secret?', checking: 'Identity and security model.', mistake: 'Storing credentials in code instead of using managed identities.' },
    { q: 'When would you use App Service vs AKS vs Azure Functions?', short: 'App Service for managed web apps, AKS for container orchestration, Functions for event-driven serverless.', strong: 'App Service is a managed PaaS for web apps/APIs with easy scaling. AKS gives full Kubernetes for complex, portable, microservice workloads needing orchestration control. Functions are event-driven serverless for short, scalable tasks with consumption billing. Choose by control, workload shape and operational overhead.', followUp: 'What are the cold-start trade-offs of Functions?', checking: 'Compute-selection judgment.', mistake: 'Using AKS for a simple web app that App Service would run cheaper.' },
    { q: 'Compare Azure SQL Database and Cosmos DB.', short: 'Azure SQL is managed relational; Cosmos DB is globally-distributed multi-model NoSQL.', strong: 'Azure SQL Database is a managed relational engine for structured, transactional data with SQL. Cosmos DB is a globally distributed, low-latency NoSQL service (multiple APIs) with tunable consistency and horizontal partitioning — great for global scale and flexible schemas. Choose by data shape, consistency needs and scale.', followUp: 'What are Cosmos DB’s consistency levels and their trade-offs?', checking: 'Data-service selection.', mistake: 'Picking Cosmos DB for relational, join-heavy workloads.' },
    { q: 'How do you secure secrets and configuration in Azure?', short: 'Azure Key Vault for secrets/keys/certs, accessed via managed identity; App Configuration for settings.', strong: 'Store secrets, keys and certificates in Azure Key Vault and access them with a managed identity — never in code or plain config. Use Azure App Configuration for feature flags and settings, and enable Key Vault references in App Service/Functions. Scope access with RBAC and rotate secrets.', followUp: 'How does a Key Vault reference in App Service avoid storing the secret?', checking: 'Secret-management practice.', mistake: 'Putting connection strings in appsettings committed to source.' },
    { q: 'What is Infrastructure as Code on Azure (Bicep/ARM/Terraform)?', short: 'Declarative templates to provision Azure resources repeatably and reviewably.', strong: 'Bicep (and underlying ARM) and Terraform declare Azure infrastructure as version-controlled code, enabling repeatable, reviewable deployments and drift detection. Bicep is Azure-native and concise; Terraform is multi-cloud. Use modules, parameterize environments, and deploy through CI/CD.', followUp: 'Bicep vs Terraform — when would you pick each?', checking: 'IaC awareness on Azure.', mistake: 'Clicking resources in the portal with no IaC.' },
    { q: 'How do you monitor and troubleshoot Azure workloads?', short: 'Azure Monitor, Application Insights, Log Analytics and alerts give metrics, logs and traces.', strong: 'Azure Monitor collects metrics and logs; Application Insights adds APM (requests, dependencies, traces, exceptions); Log Analytics queries logs with KQL; and alerts/action groups notify on conditions. Together they turn "it is slow" into a root cause. Instrument apps and set actionable alerts tied to SLOs.', followUp: 'What language do you use to query Log Analytics?', checking: 'Operability on Azure.', mistake: 'No instrumentation, debugging blind in production.' },
  ],
  'data-engineering-interview-questions': [
    { q: 'What is the difference between ETL and ELT, and when do you use each?', short: 'ETL transforms before loading; ELT loads raw then transforms in the warehouse.', strong: 'ETL transforms data before loading into the target — good when the target is expensive or transformations are heavy and pre-defined. ELT loads raw data into a powerful warehouse/lakehouse (Snowflake, BigQuery, Databricks) and transforms there with SQL — the modern default, leveraging cheap storage and scalable compute for flexibility and reprocessing.', followUp: 'Why has ELT become the default in modern stacks?', checking: 'Modern data-architecture understanding.', mistake: 'Assuming ETL is always right regardless of the platform.' },
    { q: 'How do you design a scalable data pipeline?', short: 'Ingest → store → transform → serve, with idempotency, partitioning, orchestration and observability.', strong: 'Separate ingestion (batch/stream), storage (data lake/warehouse), transformation (SQL/Spark) and serving. Make steps idempotent and re-runnable, partition data for parallelism and pruning, orchestrate with a scheduler (Airflow/dbt), add data-quality checks, and monitor for failures and freshness. Design for schema evolution and backfills from day one.', followUp: 'How do you handle a late-arriving or malformed record?', checking: 'End-to-end pipeline design.', mistake: 'A brittle, non-idempotent pipeline with no quality checks.' },
    { q: 'What is data partitioning and why does it matter?', short: 'Splitting data by a key (often date) so queries scan less and jobs parallelize.', strong: 'Partitioning divides a dataset by a column (commonly date) so the engine reads only relevant partitions (partition pruning) and can process them in parallel. Good partitioning slashes query cost and runtime; over-partitioning creates many tiny files and overhead. Choose a key that matches query filters and data volume.', followUp: 'What problem do too many small partitions cause?', checking: 'Performance and storage understanding.', mistake: 'Partitioning on a high-cardinality column, creating tiny-file problems.' },
    { q: 'Explain batch vs streaming processing.', short: 'Batch processes bounded data on a schedule; streaming processes unbounded data continuously.', strong: 'Batch processes large, bounded datasets periodically — simple and cost-efficient for non-urgent analytics. Streaming (Kafka + Flink/Spark Structured Streaming) processes events continuously for low-latency use cases (fraud, monitoring, real-time dashboards), but adds complexity around state, ordering and exactly-once semantics. Many systems use both (lambda/kappa).', followUp: 'What makes exactly-once hard in streaming?', checking: 'Processing-model understanding.', mistake: 'Using streaming complexity where a batch job would do.' },
    { q: 'How do you ensure data quality in a pipeline?', short: 'Validate schema, nulls, ranges, uniqueness and freshness; fail loudly and quarantine bad data.', strong: 'Add automated checks for schema conformance, null/range/format constraints, uniqueness, referential integrity and freshness (tools like dbt tests or Great Expectations). Quarantine or reject bad rows rather than silently dropping them, alert on failures, and track data lineage so you can trace issues back to the source.', followUp: 'What do you do with rows that fail validation?', checking: 'Data-reliability discipline.', mistake: 'Silently dropping bad data and reporting wrong numbers.' },
    { q: 'What is a data lakehouse?', short: 'An architecture combining a data lake’s cheap storage with warehouse-like management (e.g., Delta Lake).', strong: 'A lakehouse (Delta Lake, Iceberg, Hudi on Databricks/Spark) adds ACID transactions, schema enforcement, time travel and performance to cheap object-storage data lakes — unifying data engineering, BI and ML on one copy of data instead of separate lake and warehouse silos. It is a dominant 2026 pattern.', followUp: 'What does Delta Lake add over plain Parquet on a lake?', checking: 'Current data-platform knowledge.', mistake: 'Confusing a lakehouse with a traditional warehouse or raw lake.' },
    { q: 'How do you optimize a slow Spark job?', short: 'Fix skew and shuffles, cache wisely, tune partitions, and avoid wide transformations where possible.', strong: 'Profile the Spark UI for skew, excessive shuffles and spills. Mitigate data skew (salting, broadcast joins for small tables), right-size partitions, cache reused datasets, prune columns/partitions early, and prefer narrow transformations. Avoid collecting large data to the driver. Measure stage-by-stage.', followUp: 'When would you use a broadcast join?', checking: 'Distributed-processing tuning.', mistake: 'Blaming the cluster size instead of fixing skew and shuffles.' },
    { q: 'What is idempotency and why is it critical in data pipelines?', short: 'Re-running the same job produces the same result — essential for safe retries and backfills.', strong: 'An idempotent pipeline step can run multiple times without duplicating or corrupting data — achieved via deterministic keys, upserts/merge, overwrite-by-partition, and dedup. It is critical because failures, retries and backfills are inevitable; without idempotency you get duplicates and inconsistent state.', followUp: 'How do you make an append-based load idempotent?', checking: 'Reliability fundamentals.', mistake: 'Append-only loads that duplicate data on retry.' },
  ],
  'mlops-interview-questions': [
    { q: 'What is MLOps and how does it differ from DevOps?', short: 'MLOps applies DevOps practices to ML, adding data and model lifecycle concerns.', strong: 'MLOps operationalizes machine learning: automated training, deployment, monitoring and governance of models. Beyond DevOps it must handle data versioning, model versioning, experiment tracking, drift/decay, and reproducibility — because ML behavior depends on data, not just code. The unit of change is code + data + model, not just code.', followUp: 'Why does model performance degrade over time even with no code change?', checking: 'Understanding of what makes ML ops different.', mistake: 'Treating a model like a static binary you deploy once.' },
    { q: 'How do you design a model training and deployment pipeline?', short: 'Automate data prep, training, evaluation, registry, and gated deployment with monitoring.', strong: 'Build a pipeline that ingests and validates data, trains and evaluates against a baseline, registers the model with metadata/lineage, and deploys behind a gate (offline metrics + shadow/canary) — then monitors in production. Everything is versioned and reproducible so you can roll back and retrain on a schedule or trigger.', followUp: 'What gates would you require before promoting a model to production?', checking: 'End-to-end MLOps design.', mistake: 'Manually training and copying model files with no evaluation gate.' },
    { q: 'What is model drift and how do you detect it?', short: 'Drift is when data or relationships change so the model degrades; detect via monitoring.', strong: 'Data drift is a change in input distributions; concept drift is a change in the input→output relationship. Detect by monitoring input feature distributions, prediction distributions and (when labels arrive) live accuracy against baselines, with statistical tests and alerts. Trigger retraining or rollback when drift crosses thresholds.', followUp: 'How do you monitor accuracy when ground-truth labels are delayed?', checking: 'Production ML reliability.', mistake: 'Deploying a model with no drift or performance monitoring.' },
    { q: 'What is a feature store and why is it useful?', short: 'A central system for computing, storing and serving consistent features for training and inference.', strong: 'A feature store manages feature computation, storage, versioning and serving so the same feature logic is used in training and online inference — eliminating training/serving skew. It also enables reuse across teams and point-in-time correctness for training data. Useful once feature reuse and consistency become pain points.', followUp: 'What is training/serving skew and how does a feature store prevent it?', checking: 'Awareness of a core MLOps component.', mistake: 'Recomputing features differently in training vs serving.' },
    { q: 'How do you version data and models for reproducibility?', short: 'Version datasets, code, config and model artifacts with lineage in a registry.', strong: 'Reproducibility needs versioned data (DVC/lakehouse snapshots), code (git), environment/config, and model artifacts in a model registry with metadata linking each model to its training data, code and metrics. This lets you reproduce, audit and roll back any model. Without it, "which data trained this?" becomes unanswerable.', followUp: 'A model in production misbehaves — how do you trace what trained it?', checking: 'Governance and reproducibility.', mistake: 'Only versioning code, not data and artifacts.' },
    { q: 'What deployment strategies suit ML models?', short: 'Shadow, canary and A/B deployments reduce risk when promoting a new model.', strong: 'Shadow deployment runs the new model alongside production without serving its results, to compare safely. Canary routes a small share of traffic to validate on live data. A/B tests compare business metrics between models. These limit blast radius because offline metrics don’t guarantee online performance.', followUp: 'Why is offline evaluation not enough before full rollout?', checking: 'Safe ML release practice.', mistake: 'Swapping models in production with no shadow/canary.' },
    { q: 'How do you serve models at scale and control cost/latency?', short: 'Choose real-time vs batch, right-size compute, batch requests, cache, and autoscale.', strong: 'Decide between real-time endpoints and batch scoring by latency needs. Optimize with request batching, model optimization (quantization/distillation), caching repeat inputs, GPU/CPU right-sizing and autoscaling. Monitor latency, throughput and cost per prediction. For LLMs, token/cost control matters even more.', followUp: 'When is batch scoring a better choice than a real-time endpoint?', checking: 'Serving and cost awareness.', mistake: 'Defaulting to always-on GPU endpoints for infrequent predictions.' },
  ],
  'sre-interview-questions': [
    { q: 'What are SLIs, SLOs and error budgets?', short: 'SLIs measure reliability, SLOs set targets, and the error budget is the allowed unreliability.', strong: 'An SLI is a measured indicator (e.g., success rate, latency). An SLO is the target for that SLI (e.g., 99.9% success). The error budget is 1 − SLO — the acceptable amount of failure. When the budget is healthy you can ship faster; when it is exhausted you slow down and prioritize reliability. It aligns dev velocity with reliability.', followUp: 'What should a team do when it burns through its error budget?', checking: 'Core SRE philosophy.', mistake: 'Chasing 100% reliability instead of a meaningful SLO.' },
    { q: 'How do you approach incident response?', short: 'Detect, triage, mitigate, communicate, resolve, then a blameless postmortem.', strong: 'Acknowledge the alert, assess severity and blast radius, mitigate first (rollback, failover, scale, feature flag) before root-causing, assign clear roles (incident commander, comms), keep stakeholders updated, then fix and verify. Afterward run a blameless postmortem with concrete action items so it does not recur.', followUp: 'Why mitigate before finding the root cause?', checking: 'Operational maturity.', mistake: 'Debugging root cause while users remain down.' },
    { q: 'What is toil and how do SREs manage it?', short: 'Toil is manual, repetitive, automatable operational work; SREs cap and automate it.', strong: 'Toil is manual, repetitive, tactical work that scales with service size and has no lasting value (e.g., manual restarts, hand-run runbooks). SRE practice caps toil (often ~50%) and invests the rest in automation and engineering that eliminates it — otherwise ops work grows unbounded with the system.', followUp: 'How do you decide what toil to automate first?', checking: 'SRE engineering mindset.', mistake: 'Accepting endless manual ops instead of automating.' },
    { q: 'How do you design effective monitoring and alerting?', short: 'Alert on user-facing symptoms (SLOs), keep alerts actionable, and use the four golden signals.', strong: 'Monitor the four golden signals — latency, traffic, errors, saturation — and alert primarily on symptoms users feel (SLO burn) rather than every cause. Every alert should be actionable and urgent; page-worthy alerts need a runbook. Reduce noise to avoid alert fatigue, and use dashboards for diagnosis.', followUp: 'What is the danger of alerting on causes instead of symptoms?', checking: 'Observability design.', mistake: 'Paging on every metric, drowning on-call in noise.' },
    { q: 'What is the difference between reliability and availability?', short: 'Availability is uptime; reliability is performing correctly over time under real conditions.', strong: 'Availability measures whether the service is up (e.g., 99.9%). Reliability is broader — the service does the right thing correctly and consistently, including correctness, latency and durability, over time. A system can be "up" but unreliable (slow, returning errors). SLOs usually capture more than raw uptime.', followUp: 'Give an example of an available but unreliable system.', checking: 'Conceptual clarity.', mistake: 'Equating a green uptime check with reliability.' },
    { q: 'How do you make deployments safe?', short: 'Progressive delivery (canary/blue-green), health checks, automated rollback and feature flags.', strong: 'Roll out gradually with canary or blue-green, gate on health/SLO checks, and automate rollback on regression. Decouple deploy from release with feature flags so you can turn features off without redeploying. Small, frequent, reversible changes are safer than big-bang releases.', followUp: 'How do feature flags reduce deployment risk?', checking: 'Release-engineering knowledge.', mistake: 'Big, infrequent releases with no automated rollback.' },
    { q: 'What is capacity planning and how do you approach it?', short: 'Forecast demand, load-test to find limits, and provision headroom with autoscaling.', strong: 'Capacity planning forecasts future load from growth and events, load/stress tests to find real limits and bottlenecks, and provisions headroom plus autoscaling to absorb spikes. Track saturation signals and cost. The goal is meeting SLOs under peak load without wasteful over-provisioning.', followUp: 'What saturation signals warn you that capacity is running out?', checking: 'Scalability planning.', mistake: 'Reacting to outages instead of planning capacity.' },
  ],
  'cloud-security-interview-questions': [
    { q: 'What is the shared responsibility model in cloud security?', short: 'The provider secures the cloud; you secure what you put in it.', strong: 'Cloud providers secure the underlying infrastructure (hardware, network, hypervisor); customers secure their data, identities, access, configurations, OS/app patching and network rules. The split shifts by service type (IaaS vs PaaS vs SaaS). Most breaches come from the customer side — misconfiguration and identity — not the provider.', followUp: 'How does the responsibility split change between IaaS and SaaS?', checking: 'Foundational cloud-security understanding.', mistake: 'Assuming the provider secures your data and config.' },
    { q: 'How do you implement least privilege and zero trust in the cloud?', short: 'Grant minimal scoped permissions, verify every request, and assume no implicit trust.', strong: 'Least privilege means granting only the permissions needed, scoped as narrowly as possible, using roles over long-lived keys and just-in-time access. Zero trust assumes no implicit trust by network location — every request is authenticated, authorized and encrypted, with continuous verification and segmentation. Together they shrink the blast radius of any compromise.', followUp: 'How do you find and remove over-permissioned identities?', checking: 'Identity-first security thinking.', mistake: 'Broad wildcard permissions and standing admin access.' },
    { q: 'What are the most common cloud misconfigurations, and how do you prevent them?', short: 'Public storage, open security groups, over-permissive IAM; prevent with policy-as-code and scanning.', strong: 'Frequent issues: publicly exposed object storage, wide-open network/security groups, over-permissive IAM, unencrypted data, and disabled logging. Prevent with secure defaults, IaC with policy-as-code (guardrails), automated posture management (CSPM) scanning, and least-privilege reviews. Catch them before deploy, not after a breach.', followUp: 'How does policy-as-code stop a public bucket from being created?', checking: 'Preventive security practice.', mistake: 'Relying on manual review to catch misconfigurations.' },
    { q: 'How do you secure secrets and encryption keys in the cloud?', short: 'Use a managed secrets/KMS service, access via identity, encrypt in transit and at rest, and rotate.', strong: 'Store secrets and keys in a managed service (Key Vault/KMS/Secrets Manager), access them via workload identities (not embedded credentials), encrypt data in transit (TLS) and at rest, and rotate regularly. Scope access with least privilege and audit usage. Never commit secrets to source or bake them into images.', followUp: 'Why is a managed identity better than an embedded API key?', checking: 'Secret/key management.', mistake: 'Hardcoding keys in code or config.' },
    { q: 'How do you secure a Kubernetes cluster?', short: 'RBAC, network policies, pod security, image scanning, secrets management and audit logging.', strong: 'Lock down the API with RBAC and least privilege, restrict pod-to-pod traffic with network policies, enforce pod security standards (no privileged/root), scan images and admit only trusted ones, manage secrets externally, encrypt etcd, and enable audit logging. Keep nodes and the control plane patched.', followUp: 'What does a network policy protect against that RBAC does not?', checking: 'Container-security depth.', mistake: 'Running privileged pods with a wide-open cluster.' },
    { q: 'How do you approach threat detection and incident response in the cloud?', short: 'Centralize logs, use cloud-native threat detection, alert on anomalies, and have an IR runbook.', strong: 'Aggregate logs (CloudTrail/Activity logs, flow logs) into a SIEM, enable cloud-native detection (GuardDuty/Defender), and alert on anomalous identity, network and API activity. Have an incident-response runbook: contain (isolate/revoke), investigate, eradicate, recover, and learn. Practice with tabletop exercises.', followUp: 'What is the first containment step if an access key is leaked?', checking: 'Detection and response readiness.', mistake: 'No centralized logging or IR plan until after an incident.' },
    { q: 'What is DevSecOps and how do you shift security left?', short: 'Embed automated security into the CI/CD pipeline so issues are caught early.', strong: 'DevSecOps integrates security into development and delivery: secret scanning, SAST/DAST, dependency (SCA) scanning, IaC scanning and image scanning run automatically in CI/CD, with policy gates. Shifting left catches vulnerabilities before production, where they are far cheaper to fix, and makes security a shared responsibility.', followUp: 'Which security scans would you run in a pull-request pipeline?', checking: 'Modern secure-delivery practice.', mistake: 'Treating security as a final gate instead of continuous.' },
  ],
  'microservices-interview-questions': [
    { q: 'What are microservices and what are their trade-offs vs a monolith?', short: 'Independently deployable services split by business capability; flexibility at the cost of complexity.', strong: 'Microservices decompose an app into small, independently deployable services owned by teams, enabling independent scaling, deployment and tech choices. The trade-off is distributed-systems complexity: network calls, data consistency, observability and operational overhead. Start with a modular monolith and split only when the benefits outweigh that complexity.', followUp: 'When is a monolith the better choice?', checking: 'Architectural judgment, not hype.', mistake: 'Jumping to microservices prematurely for a small app.' },
    { q: 'How do you handle data consistency across microservices?', short: 'Each service owns its data; use eventual consistency, sagas and events instead of distributed transactions.', strong: 'Each service owns its database, so you avoid distributed ACID transactions. Use the saga pattern (choreography or orchestration) with compensating actions for multi-service workflows, and events for eventual consistency. Design for idempotency and handle partial failures explicitly. Two-phase commit across services is usually an anti-pattern.', followUp: 'What is a compensating transaction in a saga?', checking: 'Distributed-data understanding.', mistake: 'Trying to use a shared database or 2PC across services.' },
    { q: 'How do services communicate, and when do you choose sync vs async?', short: 'Sync (REST/gRPC) for request/response; async (events/messaging) for decoupling and resilience.', strong: 'Synchronous REST/gRPC suits immediate request/response but couples availability. Asynchronous messaging/events (Kafka, queues) decouples services, absorbs spikes and improves resilience, at the cost of eventual consistency and added complexity. Many systems mix both; prefer async for cross-service workflows and events.', followUp: 'What happens to a synchronous chain if one service is slow?', checking: 'Communication-pattern judgment.', mistake: 'Long synchronous call chains that cascade failures.' },
    { q: 'How do you make microservices resilient?', short: 'Timeouts, retries with backoff, circuit breakers, bulkheads and fallbacks.', strong: 'Protect against downstream failure with sensible timeouts, retries with exponential backoff and jitter (only for idempotent calls), circuit breakers to stop hammering a failing service, bulkheads to isolate resources, and graceful fallbacks. Without these, one slow dependency can cascade into a full outage.', followUp: 'Why can naive retries make an outage worse?', checking: 'Resilience-pattern knowledge.', mistake: 'Retrying aggressively with no backoff or circuit breaker.' },
    { q: 'What is an API gateway and why use one?', short: 'A single entry point handling routing, auth, rate limiting and cross-cutting concerns.', strong: 'An API gateway is the front door to microservices, handling routing, authentication, rate limiting, TLS termination and request aggregation — so clients don’t call services directly and cross-cutting concerns live in one place. Combined with service discovery, it decouples clients from internal topology.', followUp: 'What is the risk of putting too much logic in the gateway?', checking: 'Edge-architecture understanding.', mistake: 'Exposing every service directly with duplicated auth logic.' },
    { q: 'How do you achieve observability across microservices?', short: 'Correlated logs, metrics and distributed tracing tied together by request/trace IDs.', strong: 'Instrument services to emit structured logs, metrics and distributed traces (OpenTelemetry), propagating a trace/correlation ID across calls so you can follow a request end-to-end. Centralize in tracing/metrics backends. Without distributed tracing, debugging a slow request across many services is nearly impossible.', followUp: 'How does a trace ID help debug a slow cross-service request?', checking: 'Distributed observability.', mistake: 'Per-service logs with no correlation across the call chain.' },
    { q: 'How do you handle service discovery and configuration?', short: 'A registry (or platform DNS) for discovery; externalized, centralized configuration.', strong: 'Services find each other via a registry (Consul/Eureka) or platform DNS (Kubernetes Services), so instances can scale and move. Configuration is externalized (config server, ConfigMaps/Secrets, environment) rather than baked in, enabling per-environment settings and safe rotation. Both decouple deployment topology from code.', followUp: 'How does Kubernetes provide service discovery out of the box?', checking: 'Operational microservices knowledge.', mistake: 'Hardcoding service hostnames and config in the app.' },
  ],
  'nodejs-interview-questions': [
    { q: 'How does the Node.js event loop work?', short: 'A single-threaded loop offloads I/O and runs callbacks in phases, enabling non-blocking concurrency.', strong: 'Node runs JavaScript on a single thread but offloads I/O to the libuv thread pool/OS, then processes completed callbacks through event-loop phases (timers, pending, poll, check, close). This non-blocking model handles many concurrent I/O operations efficiently — current to Node.js 24 LTS. CPU-bound work blocks the loop, so offload it.', followUp: 'What happens to the event loop during a heavy synchronous computation?', checking: 'Core runtime understanding.', mistake: 'Thinking Node is multi-threaded for your JS code by default.' },
    { q: 'What is the difference between process.nextTick, microtasks and setImmediate?', short: 'nextTick and promise microtasks run before the loop continues; setImmediate runs in the check phase.', strong: 'process.nextTick callbacks and Promise microtasks drain before the event loop proceeds to the next phase (nextTick even before other microtasks). setImmediate runs in the check phase after poll. Misusing nextTick can starve the loop. Understanding the ordering matters for predictable async behavior.', followUp: 'How can overusing process.nextTick starve I/O?', checking: 'Deep async ordering knowledge.', mistake: 'Assuming setImmediate and nextTick run at the same time.' },
    { q: 'How do you handle CPU-bound work in Node.js?', short: 'Offload to worker threads, child processes, or an external service — never block the loop.', strong: 'Since a long synchronous task blocks the single event loop and stalls all requests, offload CPU-bound work to worker_threads, a child process/cluster, or a separate service/queue. Keep the main loop for I/O orchestration. This preserves responsiveness under load.', followUp: 'Worker threads vs cluster — when do you use each?', checking: 'Scaling Node correctly.', mistake: 'Running heavy computation on the main thread.' },
    { q: 'How do you handle errors in async Node.js code?', short: 'try/catch with async/await, handle promise rejections, and centralize error middleware.', strong: 'Use try/catch around await, always handle promise rejections (unhandledRejection can crash the process), and in Express centralize errors with error-handling middleware. Distinguish operational errors (retry/respond) from programmer errors (fail fast). Validate inputs and never swallow errors silently.', followUp: 'What happens on an unhandled promise rejection in modern Node?', checking: 'Robust error handling.', mistake: 'Forgetting to catch rejected promises.' },
    { q: 'How do you build a scalable REST API in Node.js?', short: 'Async handlers, input validation, middleware, clustering/horizontal scaling, and caching.', strong: 'Use a framework (Express/Fastify) with async handlers, validate inputs, centralize auth and errors in middleware, keep handlers non-blocking, and scale horizontally (cluster/PM2 or containers behind a load balancer) since one process uses one core. Add caching, rate limiting and observability.', followUp: 'Why does a single Node process only use one CPU core?', checking: 'API and scaling understanding.', mistake: 'Running one process on a multi-core box with no clustering.' },
    { q: 'What are streams and why are they useful?', short: 'Streams process data in chunks, enabling low-memory handling of large data.', strong: 'Streams (readable, writable, duplex, transform) process data piece by piece instead of loading it all into memory — ideal for large files, network data and pipelines via pipe(). They improve memory efficiency and time-to-first-byte. Backpressure handling keeps fast producers from overwhelming slow consumers.', followUp: 'What problem does backpressure solve?', checking: 'Efficient data handling.', mistake: 'Buffering huge payloads fully in memory.' },
    { q: 'How do you manage configuration, secrets and security in Node apps?', short: 'Env-based config, a secrets manager, input validation, and dependency scanning.', strong: 'Keep config in environment variables (12-factor), store secrets in a manager (not .env in git), validate and sanitize all input, use parameterized queries, set security headers (helmet), keep dependencies patched (npm audit/SCA), and avoid running as root. Supply-chain risk via npm packages is real — vet dependencies.', followUp: 'How do you reduce npm supply-chain risk?', checking: 'Security awareness.', mistake: 'Committing secrets and ignoring dependency vulnerabilities.' },
  ],
  'angular-interview-questions': [
    { q: 'How is Angular architected (components, modules, services, DI)?', short: 'Components with templates, services via DI, organized into modules or standalone components.', strong: 'Angular apps are trees of components (template + class), with shared logic in injectable services provided through Angular’s DI. Historically organized by NgModules; modern Angular (current: Angular 22) favors standalone components and signals. Understanding DI, change detection and the component lifecycle is core.', followUp: 'What are standalone components and why did Angular move toward them?', checking: 'Current Angular architecture knowledge.', mistake: 'Only knowing old NgModule-based Angular.' },
    { q: 'What are Angular signals and how do they change state management?', short: 'Signals are reactive values that update the UI granularly without Zone.js overhead.', strong: 'Signals (stable in recent Angular) are reactive primitives that hold a value and notify consumers on change, enabling fine-grained, efficient updates and a path toward zoneless change detection. They simplify local reactive state and computed values, complementing or replacing some RxJS use for state.', followUp: 'How do signals differ from RxJS observables?', checking: 'Awareness of modern Angular reactivity.', mistake: 'Being unaware of signals in current Angular.' },
    { q: 'How does Angular change detection work?', short: 'Angular checks components for changes; OnPush and signals limit checks for performance.', strong: 'By default Angular checks the component tree on events/async via Zone.js. OnPush change detection only re-checks a component when its inputs change (by reference) or an event fires, cutting work. Signals enable even more granular, zoneless updates. Understanding this is key to performance.', followUp: 'How does OnPush reduce change-detection work?', checking: 'Performance understanding.', mistake: 'Leaving everything on default change detection in large apps.' },
    { q: 'What is RxJS and how is it used in Angular?', short: 'A reactive library for async streams; used for HTTP, events and state via observables.', strong: 'RxJS models async data as observable streams you compose with operators (map, switchMap, debounceTime). Angular uses it for HttpClient, router events, forms and reactive state. Key skills: choosing the right flattening operator (switchMap vs mergeMap), and unsubscribing (async pipe or takeUntil) to avoid leaks.', followUp: 'switchMap vs mergeMap — when do you use each?', checking: 'Reactive-programming competence.', mistake: 'Nested subscribes and forgetting to unsubscribe.' },
    { q: 'How do you handle forms in Angular?', short: 'Template-driven for simple forms, reactive forms for complex, testable, dynamic forms.', strong: 'Template-driven forms are quick for simple cases. Reactive forms build the model in code (FormGroup/FormControl), giving explicit, testable, dynamic control with synchronous access and custom validators. For anything complex or dynamic, reactive forms are preferred.', followUp: 'Why are reactive forms easier to unit test?', checking: 'Practical Angular forms.', mistake: 'Forcing template-driven forms onto complex scenarios.' },
    { q: 'How do you optimize performance in an Angular app?', short: 'OnPush, trackBy, lazy loading, signals, and avoiding heavy work in templates.', strong: 'Use OnPush change detection and signals, trackBy in *ngFor to avoid re-rendering lists, lazy-load feature routes to shrink initial bundles, avoid function calls/heavy pipes in templates, and use pure pipes. Profile with Angular DevTools. These cut both change-detection and bundle costs.', followUp: 'Why does calling a function in a template hurt performance?', checking: 'Optimization knowledge.', mistake: 'Binding to method calls that run every change-detection cycle.' },
    { q: 'How do lazy loading and routing work in Angular?', short: 'The router loads feature routes on demand, reducing the initial bundle.', strong: 'Angular’s router maps paths to components and can lazy-load feature areas (loadChildren/loadComponent) so their code downloads only when navigated to — shrinking the initial bundle and speeding first load. Combine with route guards for auth and preloading strategies for perceived speed.', followUp: 'How does lazy loading affect initial load time?', checking: 'Routing and bundling understanding.', mistake: 'Eagerly loading the whole app in one bundle.' },
  ],
  'ai-ml-interview-questions': [
    { q: 'Explain the bias-variance trade-off.', short: 'High bias underfits, high variance overfits; you tune model complexity to balance both.', strong: 'Bias is error from overly simple assumptions (underfitting); variance is sensitivity to training-data noise (overfitting). Increasing model complexity lowers bias but raises variance. You balance them via regularization, cross-validation, more data and appropriate complexity to minimize total generalization error.', followUp: 'How does regularization affect this trade-off?', checking: 'Core ML theory.', mistake: 'Optimizing training accuracy while ignoring generalization.' },
    { q: 'How do you handle an imbalanced dataset?', short: 'Resample, reweight, use the right metrics, and pick threshold by business cost.', strong: 'Address imbalance with resampling (oversample minority/SMOTE or undersample majority), class weighting, and choosing metrics beyond accuracy (precision/recall, F1, PR-AUC). Tune the decision threshold to the cost of false positives vs negatives. Accuracy is misleading when one class dominates.', followUp: 'Why is accuracy a poor metric for a 99:1 imbalance?', checking: 'Practical modeling judgment.', mistake: 'Reporting high accuracy on a skewed dataset.' },
    { q: 'What is overfitting and how do you prevent it?', short: 'The model memorizes training data; prevent with regularization, more data and validation.', strong: 'Overfitting is when a model fits noise in training data and generalizes poorly. Prevent it with regularization (L1/L2, dropout), more/augmented data, simpler models, early stopping, and cross-validation to detect it. The gap between training and validation performance is the tell.', followUp: 'How does early stopping help?', checking: 'Generalization understanding.', mistake: 'Trusting training accuracy without a validation set.' },
    { q: 'How do you choose evaluation metrics for a model?', short: 'Match the metric to the task and business cost — not just accuracy.', strong: 'For classification use precision/recall/F1/ROC-AUC/PR-AUC depending on imbalance and error costs; for regression use RMSE/MAE/R². Ranking uses NDCG/MAP. Always tie the metric to the business objective and the cost of each error type, and evaluate on held-out data.', followUp: 'When do you prefer PR-AUC over ROC-AUC?', checking: 'Evaluation maturity.', mistake: 'Defaulting to accuracy for every problem.' },
    { q: 'Explain the difference between supervised, unsupervised and reinforcement learning.', short: 'Supervised uses labels, unsupervised finds structure, RL learns from rewards.', strong: 'Supervised learning maps inputs to labeled outputs (classification/regression). Unsupervised finds structure without labels (clustering, dimensionality reduction). Reinforcement learning trains an agent via rewards from interacting with an environment. The choice depends on whether you have labels and whether it is a sequential-decision problem.', followUp: 'Give a real use case for each.', checking: 'Foundational ML taxonomy.', mistake: 'Confusing clustering with classification.' },
    { q: 'How would you deploy and monitor an ML model in production?', short: 'Serve via API/batch, version it, and monitor drift, latency and accuracy.', strong: 'Package the model with its preprocessing, serve via a real-time endpoint or batch job, version it in a registry, and monitor input drift, prediction distributions, latency and (when labels arrive) live accuracy — with alerts and a retraining/rollback path. Offline metrics don’t guarantee production performance.', followUp: 'What signals tell you a deployed model is degrading?', checking: 'Production ML awareness.', mistake: 'Treating deployment as the finish line with no monitoring.' },
    { q: 'What is feature engineering and why does it matter?', short: 'Transforming raw data into informative features that improve model performance.', strong: 'Feature engineering creates, transforms and selects inputs (scaling, encoding, aggregations, domain features) so models can learn effectively. For classical ML it often matters more than the algorithm. Guard against data leakage (using future/label-derived info) and ensure the same transforms run in training and serving.', followUp: 'What is data leakage and how do you avoid it?', checking: 'Practical modeling skill.', mistake: 'Leaking target information into features.' },
  ],
  'llm-interview-questions': [
    { q: 'How does a transformer work at a high level?', short: 'Self-attention lets each token weigh all others, capturing context in parallel.', strong: 'Transformers use self-attention so every token attends to every other token, weighting relevance, combined with feed-forward layers and positional information. This captures long-range context and trains in parallel (unlike RNNs). Modern LLMs are large decoder-style transformers trained to predict the next token.', followUp: 'Why did transformers replace RNNs for language?', checking: 'Architecture fundamentals.', mistake: 'Describing LLMs as simple lookup or Markov models.' },
    { q: 'What is the difference between fine-tuning, RAG and prompting?', short: 'Prompting steers, RAG adds external knowledge, fine-tuning changes behavior/format.', strong: 'Prompting shapes output with instructions/examples at inference. RAG injects retrieved, up-to-date or proprietary context so the model grounds answers in your data. Fine-tuning updates weights to change tone, format or domain behavior. Start with prompting, add RAG for knowledge, fine-tune for behavior when prompt+retrieval isn’t enough.', followUp: 'Why not fine-tune to add frequently-changing facts?', checking: 'Practical LLM strategy.', mistake: 'Fine-tuning to inject knowledge that changes daily.' },
    { q: 'What is a context window and why does it matter?', short: 'The max tokens a model can consider at once; it bounds input + output.', strong: 'The context window is the token budget for prompt plus generation. It limits how much document/history you can include, drives cost and latency, and forces strategies like chunking, retrieval and summarization for large inputs. Bigger windows help but don’t eliminate the need for good retrieval and context management.', followUp: 'How do you handle a document larger than the context window?', checking: 'Practical LLM constraints.', mistake: 'Assuming you can just paste unlimited text.' },
    { q: 'How do you control LLM output cost and latency?', short: 'Right-size the model, cap tokens, cache, batch, and use retrieval to shorten prompts.', strong: 'Choose the smallest model that meets quality, cap max tokens, cache repeated prompts/responses, stream output, batch where possible, and keep prompts lean via good retrieval instead of stuffing context. Monitor tokens per request. For scale, route easy queries to cheaper models.', followUp: 'How does prompt size affect cost?', checking: 'Production LLM economics.', mistake: 'Sending huge prompts to the largest model for every request.' },
    { q: 'How do you evaluate an LLM or LLM feature?', short: 'Task-specific metrics, groundedness checks, and human or LLM-as-judge review.', strong: 'Define success per task (correctness, groundedness, relevance, safety, format), build eval sets, and combine automated metrics, LLM-as-judge (carefully) and human review for high-stakes cases. Track regressions across prompt/model changes like tests. Vibe-checking alone is not evaluation.', followUp: 'How do you catch hallucinations systematically?', checking: 'Evaluation rigor.', mistake: 'Shipping on anecdotal "looks good" testing.' },
    { q: 'What causes hallucinations and how do you reduce them?', short: 'Models predict plausible text; ground with retrieval, constrain, cite and verify.', strong: 'Hallucinations arise because LLMs generate statistically plausible text, not verified facts. Reduce them by grounding in retrieved authoritative context, instructing the model to say "I don’t know", requiring citations, constraining to schemas, lowering temperature for factual tasks, and adding a verification pass for high-stakes output.', followUp: 'How would you make a model abstain when it lacks context?', checking: 'Reliability engineering.', mistake: 'Assuming a bigger model removes hallucination.' },
    { q: 'What are temperature and top-p, and how do they affect output?', short: 'They control randomness/diversity of generation.', strong: 'Temperature scales the probability distribution — lower is more deterministic/focused, higher is more creative/varied. Top-p (nucleus) samples from the smallest set of tokens whose cumulative probability exceeds p. Use low temperature for factual/structured tasks and higher for creative ones. Tune per use case.', followUp: 'What temperature would you use for a data-extraction task?', checking: 'Practical generation control.', mistake: 'Using high temperature for tasks needing consistency.' },
  ],
  'rag-interview-questions': [
    { q: 'Walk through the components of a RAG pipeline.', short: 'Ingest → chunk → embed → store → retrieve → (re-rank) → generate with grounding.', strong: 'A RAG pipeline ingests documents, chunks them thoughtfully, embeds chunks, stores them in a vector DB with metadata, retrieves top-k relevant chunks for a query (often hybrid keyword+vector), optionally re-ranks, then prompts the LLM with that context and citations. Evaluation and guardrails wrap it. Retrieval quality drives most of the outcome.', followUp: 'Which step most often causes poor RAG answers?', checking: 'End-to-end RAG understanding.', mistake: 'Focusing on the LLM while ignoring retrieval quality.' },
    { q: 'How do you choose a chunking strategy?', short: 'Balance chunk size and overlap to preserve meaning without diluting retrieval.', strong: 'Chunk by semantic boundaries (paragraphs/sections) with a size that fits context and keeps ideas intact, plus some overlap so context isn’t cut mid-thought. Too large dilutes relevance and wastes tokens; too small loses context. Structure-aware chunking (headings, tables) and metadata improve retrieval.', followUp: 'What problem does chunk overlap solve?', checking: 'Retrieval quality knowledge.', mistake: 'Fixed tiny or huge chunks with no regard for structure.' },
    { q: 'What are embeddings and how are they used in RAG?', short: 'Vector representations of meaning used to find semantically similar chunks.', strong: 'Embeddings map text to vectors where similar meanings are close. In RAG you embed chunks and the query, then find nearest neighbors in a vector DB as candidate context. Choice of embedding model and dimensionality affects retrieval quality and cost; domain-specific embeddings can help.', followUp: 'Why might two embedding models give different retrieval quality?', checking: 'Core RAG plumbing.', mistake: 'Confusing embeddings with the generative model.' },
    { q: 'What is hybrid search and why use it?', short: 'Combining keyword (lexical) and vector (semantic) retrieval for better recall.', strong: 'Hybrid search blends lexical (BM25/keyword) and semantic (vector) retrieval, then fuses the results. It catches exact terms/codes that embeddings miss and semantic matches that keywords miss — improving recall and robustness, especially for names, IDs and rare terms. Re-ranking on top further boosts precision.', followUp: 'When does pure vector search fail?', checking: 'Retrieval design depth.', mistake: 'Assuming vector search alone is always best.' },
    { q: 'How do you evaluate RAG quality?', short: 'Measure retrieval relevance and answer groundedness/faithfulness against references.', strong: 'Evaluate retrieval (are the right chunks returned? recall/precision@k) and generation (is the answer grounded in retrieved context and correct? faithfulness, answer relevance). Use labeled eval sets, LLM-as-judge with care, and human review. Separating retrieval vs generation failures tells you what to fix.', followUp: 'How do you tell a retrieval failure from a generation failure?', checking: 'RAG evaluation rigor.', mistake: 'Only eyeballing final answers without measuring retrieval.' },
    { q: 'How do you keep RAG answers grounded and reduce hallucination?', short: 'Constrain to retrieved context, cite sources, and instruct abstention.', strong: 'Prompt the model to answer only from retrieved context, cite the source chunks, and say it cannot find the answer when context is missing rather than inventing one. Add relevance thresholds so weak retrievals don’t force a guess, and verify high-stakes answers. Grounding + citations + abstention is the core defense.', followUp: 'What do you do when retrieval returns irrelevant chunks?', checking: 'Grounding strategy.', mistake: 'Letting the model answer freely regardless of retrieval quality.' },
    { q: 'How do you keep a RAG knowledge base fresh?', short: 'Incremental ingestion, re-embedding on change, and metadata for recency.', strong: 'Set up incremental pipelines that ingest new/changed documents, re-embed and upsert them, and remove stale content, with metadata (timestamps, source) to filter or prefer recent data. Schedule or event-trigger updates so the index reflects current reality. Stale indexes are a common cause of wrong answers.', followUp: 'How would you handle a document that was deleted at the source?', checking: 'Operational RAG.', mistake: 'Building the index once and never refreshing it.' },
  ],
  'agentic-ai-interview-questions': [
    { q: 'What is an AI agent and how does it differ from a single LLM call?', short: 'An agent plans and uses tools over multiple steps toward a goal, not one response.', strong: 'An agent uses an LLM to reason about a goal, choose and call tools (search, code, APIs), observe results, and iterate over multiple steps — versus a single prompt→response call. This enables multi-step tasks but adds reliability, cost and control challenges. The value is autonomy; the risk is unpredictability.', followUp: 'What makes agents harder to make reliable than single calls?', checking: 'Understanding of the agentic paradigm.', mistake: 'Describing an agent as just a longer prompt.' },
    { q: 'How do you design tools for an agent?', short: 'Few, well-described, bounded tools with clear inputs/outputs and safe side effects.', strong: 'Give the agent a small set of well-named tools with precise descriptions and schemas, validate inputs, make side effects explicit and reversible where possible, and return concise, structured results. Too many or vague tools confuse the model; risky tools need guardrails or human approval.', followUp: 'Why can too many tools hurt agent performance?', checking: 'Practical agent design.', mistake: 'Exposing many overlapping or dangerous tools with vague docs.' },
    { q: 'How do you keep an agent reliable and prevent runaway loops?', short: 'Bound steps and cost, validate between steps, add guardrails and human-in-the-loop.', strong: 'Set max-step and budget limits, validate each step’s output, detect and break loops, add guardrails for risky actions (or require human approval), retry idempotently, and trace everything. Reliability engineering matters more than cleverness — an unbounded agent can loop or overspend fast.', followUp: 'How do you stop an agent from repeating the same failing action?', checking: 'Agentic reliability, a 2026 focus.', mistake: 'Running an agent with no step/cost limits or tracing.' },
    { q: 'What are single-agent vs multi-agent architectures, and when use each?', short: 'One capable agent is simpler; multi-agent splits roles but adds coordination cost.', strong: 'A single agent with good tools is simpler and easier to debug. Multi-agent systems assign specialized roles (planner, researcher, critic) that collaborate — useful for complex, decomposable tasks — but add coordination, latency and failure modes. Start single-agent and only add agents when a task clearly benefits.', followUp: 'What new failure modes does multi-agent introduce?', checking: 'Architecture judgment.', mistake: 'Reaching for multi-agent complexity by default.' },
    { q: 'How does an agent use memory?', short: 'Short-term context plus external stores (vector/DB) for long-term recall.', strong: 'Agents keep short-term state in the context window and use external memory (vector stores, databases) to recall facts across steps or sessions, retrieving relevant memories as needed. Good memory design avoids context bloat and keeps the agent grounded; poor memory causes forgetting or contradiction.', followUp: 'Why not just keep everything in the context window?', checking: 'Memory-design understanding.', mistake: 'Stuffing all history into context, hitting limits and cost.' },
    { q: 'How do you evaluate and observe agentic systems?', short: 'Trace every step, measure task success, and evaluate tool-use correctness.', strong: 'Trace the full reasoning/tool-call sequence, measure end-to-end task success and cost, and evaluate intermediate steps (did it pick the right tool, with valid inputs?). Use labeled task suites and replay traces to debug. Observability is essential because failures hide in the multi-step process.', followUp: 'Why is step-level tracing critical for agents?', checking: 'Agent observability.', mistake: 'Only checking the final answer, not the process.' },
    { q: 'What are the safety and security risks of agents with tool access?', short: 'Prompt injection, unsafe actions and data exfiltration; mitigate with guardrails and least privilege.', strong: 'Agents that browse or call tools are exposed to prompt injection (malicious content hijacking behavior), unintended destructive actions, and data leakage. Mitigate with least-privilege tool access, input/output validation, allow-lists, human approval for high-impact actions, sandboxing, and treating retrieved content as untrusted.', followUp: 'How does prompt injection threaten a tool-using agent?', checking: 'Agent security awareness.', mistake: 'Giving an agent powerful tools with no guardrails.' },
  ],
  'terraform-interview-questions': [
    { q: 'What is Terraform state and why does it matter?', short: 'State maps config to real resources; it must be shared and locked in a team.', strong: 'Terraform records the mapping between your configuration and real infrastructure in a state file. It’s how Terraform knows what exists and computes changes. In a team, store it remotely (S3/Azure Storage/Terraform Cloud) with locking to prevent concurrent corruption, and never edit it by hand. Losing or corrupting state is a serious problem.', followUp: 'Why is remote state with locking essential for teams?', checking: 'Core Terraform operations.', mistake: 'Keeping state locally and committing it to git.' },
    { q: 'Explain the plan/apply workflow.', short: 'plan shows the diff; apply executes it; the workflow is reviewable and idempotent.', strong: 'terraform plan computes the difference between desired config and current state, showing what will be created/changed/destroyed. apply executes that plan. This makes changes previewable and reviewable (like a PR), and idempotent — re-applying unchanged config is a no-op. Always review plans before applying, especially destroys.', followUp: 'Why review a plan before apply in production?', checking: 'Safe IaC workflow.', mistake: 'Running apply without reviewing the plan.' },
    { q: 'How do you structure reusable Terraform with modules?', short: 'Encapsulate resources into modules with inputs/outputs, reused across environments.', strong: 'Modules package a set of resources with variables (inputs) and outputs, so you reuse patterns (a VPC, a service) across environments and teams with different parameters. Keep modules focused and versioned, and compose them in root configs per environment. This avoids copy-paste and drift.', followUp: 'How do you promote the same module across dev/stage/prod?', checking: 'IaC maintainability.', mistake: 'Copy-pasting resource blocks instead of modularizing.' },
    { q: 'What is drift and how do you detect/handle it?', short: 'Drift is when real infra diverges from state; detect with plan, then reconcile.', strong: 'Drift happens when infrastructure is changed outside Terraform (manual console edits). terraform plan surfaces the difference. You reconcile by either updating config to match reality or re-applying to restore desired state (or importing unmanaged resources). Preventing manual changes is the real fix.', followUp: 'How do you bring a manually-created resource under Terraform?', checking: 'Operational IaC.', mistake: 'Making console changes that silently drift from code.' },
    { q: 'How do you manage multiple environments (dev/stage/prod)?', short: 'Separate state per environment via workspaces or, better, separate config/state directories.', strong: 'Isolate each environment’s state so a change in dev can’t affect prod — using separate backends/directories (preferred for clarity) or workspaces, parameterized via variables. Keep prod changes gated and reviewed. Shared state across environments is dangerous.', followUp: 'What’s the risk of one shared state for all environments?', checking: 'Environment-isolation practice.', mistake: 'One state file spanning all environments.' },
    { q: 'How do you handle secrets in Terraform?', short: 'Keep secrets out of code/state where possible; source from a secrets manager and mark sensitive.', strong: 'Avoid hardcoding secrets; source them from a secrets manager (Vault, cloud secret stores) or environment, mark variables/outputs as sensitive, and secure the state backend (encrypted, access-controlled) because secrets can land in state. Never commit secrets or plaintext state to source control.', followUp: 'Why is the state file a secrets-exposure risk?', checking: 'Security awareness.', mistake: 'Putting plaintext secrets in .tf files or unencrypted state.' },
    { q: 'What is the difference between count and for_each?', short: 'count creates N by index; for_each creates instances keyed by a map/set.', strong: 'count creates resources by numeric index, but removing a middle item re-indexes and can recreate resources. for_each creates instances keyed by map/set keys, so add/remove affects only that key — safer for dynamic collections. Prefer for_each for keyed, stable resource sets.', followUp: 'Why can removing an item from a count list recreate other resources?', checking: 'Practical Terraform nuance.', mistake: 'Using count for keyed collections and causing churn.' },
  ],
  'aspnet-core-interview-questions': [
    { q: 'What is the middleware pipeline and why does order matter?', short: 'An ordered chain processing requests; each middleware can act or short-circuit.', strong: 'ASP.NET Core handles requests through an ordered middleware pipeline configured at startup; each component can inspect/modify the request, short-circuit, or call next(). Order is critical — e.g., exception handling first, then routing, authentication before authorization, CORS before endpoints. Wrong order causes subtle bugs.', followUp: 'Why must UseAuthentication precede UseAuthorization?', checking: 'Core framework understanding.', mistake: 'Registering middleware in the wrong order.' },
    { q: 'How does dependency injection and service lifetime work?', short: 'Built-in container with Singleton, Scoped and Transient lifetimes injected via constructors.', strong: 'ASP.NET Core’s built-in DI registers services with a lifetime: Singleton (one for the app), Scoped (one per request), Transient (one per resolution). Constructor injection is standard. Choosing correctly matters — e.g., DbContext is Scoped; injecting a Scoped service into a Singleton (captive dependency) is a bug.', followUp: 'What is a captive dependency?', checking: 'DI/lifetime knowledge.', mistake: 'Injecting Scoped services into Singletons.' },
    { q: 'What are minimal APIs and when would you use them?', short: 'A lightweight way to define endpoints without controllers, good for small services.', strong: 'Minimal APIs let you map routes to handler delegates directly with less ceremony than MVC controllers — ideal for small services, microservices and simple endpoints. Controllers still suit large apps needing conventions, filters and model binding at scale. Choose by app size and complexity.', followUp: 'When would you still prefer controllers?', checking: 'Modern .NET awareness.', mistake: 'Being unaware of minimal APIs in current .NET.' },
    { q: 'How do you implement authentication and authorization?', short: 'Authentication schemes (JWT/cookies/OIDC) plus policy/role-based authorization.', strong: 'Configure authentication (JWT bearer for APIs, cookies for web, OIDC for SSO) and authorization with roles or policies (requirements/handlers) applied via [Authorize] or endpoint metadata. Use claims for fine-grained rules. For APIs, validate tokens properly and keep them stateless.', followUp: 'Policy-based vs role-based authorization — when each?', checking: 'Security implementation.', mistake: 'Rolling custom auth instead of using the built-in schemes.' },
    { q: 'How do you handle configuration across environments?', short: 'Layered configuration providers with environment overrides and secrets from a vault.', strong: 'ASP.NET Core layers configuration from appsettings.json, environment-specific files, environment variables and secrets, with later providers overriding earlier. Use the Options pattern (IOptions) for typed config, User Secrets in dev, and a secrets manager/Key Vault in production — never commit secrets.', followUp: 'What is the Options pattern and why use it?', checking: 'Configuration best practice.', mistake: 'Hardcoding environment-specific values.' },
    { q: 'How do you handle errors and validation in an API?', short: 'Model validation plus centralized exception handling returning consistent responses.', strong: 'Validate input with data annotations/FluentValidation and [ApiController]’s automatic 400 responses, and centralize exceptions with exception-handling middleware (or IExceptionHandler) returning ProblemDetails with correct status codes. Keep controllers clean and responses consistent.', followUp: 'What is the ProblemDetails format?', checking: 'API robustness.', mistake: 'Try/catch in every action with inconsistent error shapes.' },
    { q: 'How do you make an ASP.NET Core API performant and scalable?', short: 'Async everywhere, caching, pooling, minimal allocations, and horizontal scaling.', strong: 'Use async I/O end to end, response/output caching and distributed cache, DbContext pooling, efficient serialization, and avoid unnecessary allocations. Keep it stateless to scale horizontally behind a load balancer, add health checks, and profile hot paths. ASP.NET Core is already fast — don’t undo it with blocking calls.', followUp: 'Why do blocking calls hurt throughput here?', checking: 'Performance awareness.', mistake: 'Mixing blocking (.Result) calls into async request handling.' },
  ],
  'snowflake-interview-questions': [
    { q: 'Explain Snowflake’s architecture.', short: 'Separated storage, compute (virtual warehouses) and cloud services layers.', strong: 'Snowflake separates storage (centralized, compressed columnar data), compute (independent virtual warehouses that scale separately), and cloud services (metadata, optimization, security). This lets multiple warehouses query the same data without contention and scale compute independently of storage — the core of its elasticity and concurrency model.', followUp: 'Why does separating storage and compute matter?', checking: 'Platform fundamentals.', mistake: 'Describing it like a traditional coupled database.' },
    { q: 'What is a virtual warehouse and how do you size it?', short: 'A compute cluster for queries; size by workload and use auto-suspend to control cost.', strong: 'A virtual warehouse is an independent MPP compute cluster. Size (XS→4XL) by query complexity and concurrency, scale up for heavier queries and out (multi-cluster) for concurrency. Use auto-suspend/auto-resume so you don’t pay for idle compute. Separate warehouses per workload avoid contention.', followUp: 'How does auto-suspend save money?', checking: 'Cost/performance tuning.', mistake: 'Running one always-on oversized warehouse for everything.' },
    { q: 'How does Snowflake handle performance without manual indexes?', short: 'Micro-partitions and automatic clustering/pruning replace traditional indexes.', strong: 'Snowflake stores data in immutable micro-partitions with metadata (min/max) enabling automatic pruning — it scans only relevant partitions. There are no manual indexes; you influence pruning via natural or defined clustering keys on large tables. Good clustering plus result caching drives performance.', followUp: 'When would you define a clustering key?', checking: 'Snowflake performance model.', mistake: 'Looking for traditional indexes to tune.' },
    { q: 'What are zero-copy cloning and Time Travel?', short: 'Cloning creates instant metadata copies; Time Travel queries historical data.', strong: 'Zero-copy cloning instantly creates a clone of a table/schema/database by copying metadata, not data, so dev/test copies are cheap. Time Travel lets you query or restore data as of a past point (up to the retention period), enabling recovery from mistakes. Both leverage Snowflake’s immutable storage.', followUp: 'How would you use cloning for a safe test environment?', checking: 'Feature knowledge.', mistake: 'Physically duplicating data for test copies.' },
    { q: 'How do you load and transform data in Snowflake?', short: 'Stage and COPY INTO for loading; Streams/Tasks and dbt for transformation (ELT).', strong: 'Load via stages and COPY INTO (or Snowpipe for continuous ingestion), then transform in-warehouse (ELT) using SQL, Streams (change tracking) and Tasks (scheduling), often orchestrated with dbt. This leverages Snowflake compute for scalable transformation instead of external ETL.', followUp: 'What is Snowpipe used for?', checking: 'Data-loading practice.', mistake: 'Transforming heavily outside before loading when ELT would scale better.' },
    { q: 'How do you control costs in Snowflake?', short: 'Right-size and auto-suspend warehouses, use caching, and monitor credit usage.', strong: 'Costs are driven by warehouse compute time and storage. Control them with appropriately sized, auto-suspending warehouses, workload isolation, leveraging result/metadata caching, avoiding unnecessary large scans, setting resource monitors, and reviewing credit usage. Storage is cheap; idle/oversized compute is the usual culprit.', followUp: 'What does a resource monitor do?', checking: 'FinOps awareness.', mistake: 'Ignoring idle warehouse credits.' },
  ],
  'databricks-interview-questions': [
    { q: 'What is the lakehouse architecture?', short: 'Combines data-lake storage with warehouse reliability via Delta Lake.', strong: 'The lakehouse unifies data lakes and warehouses: cheap object storage plus a transactional layer (Delta Lake) that adds ACID, schema enforcement, time travel and performance — so engineering, BI and ML run on one copy of data. Databricks pioneered this pattern; it removes lake-vs-warehouse silos.', followUp: 'What does Delta Lake add over plain Parquet?', checking: 'Platform concept.', mistake: 'Treating a lakehouse as just a data lake.' },
    { q: 'What does Delta Lake provide?', short: 'ACID transactions, schema enforcement, time travel and performance on the lake.', strong: 'Delta Lake adds a transaction log over Parquet giving ACID writes, concurrent read/write safety, schema enforcement/evolution, time travel (versioned data), and optimizations (compaction, Z-ordering, data skipping). It turns an unreliable lake into a reliable, queryable store.', followUp: 'How does the Delta transaction log enable ACID?', checking: 'Delta fundamentals.', mistake: 'Assuming plain Parquet gives transactional guarantees.' },
    { q: 'How do you optimize a Spark job on Databricks?', short: 'Fix skew and shuffles, tune partitions, cache wisely, and use Delta optimizations.', strong: 'Profile the Spark UI for skew, shuffles and spills; mitigate skew (broadcast joins for small tables, salting), right-size partitions, prune columns/partitions, cache reused data, and use Delta features (OPTIMIZE/Z-ORDER, data skipping). Avoid collecting large data to the driver. Photon can accelerate SQL workloads.', followUp: 'When do you use a broadcast join?', checking: 'Spark performance skill.', mistake: 'Blaming cluster size instead of fixing skew/shuffles.' },
    { q: 'What is Unity Catalog and why does it matter?', short: 'Centralized governance for data and AI assets across workspaces.', strong: 'Unity Catalog provides centralized governance — fine-grained access control, lineage, auditing and discovery — for tables, files, models and more across Databricks workspaces. It replaces fragmented per-workspace permissions with a consistent, governed catalog, which is essential for enterprise data/AI security and compliance.', followUp: 'Why is centralized lineage valuable?', checking: 'Governance awareness.', mistake: 'Ignoring governance in a multi-team platform.' },
    { q: 'Explain medallion (bronze/silver/gold) architecture.', short: 'Layered Delta tables: raw → cleaned/conformed → business-ready aggregates.', strong: 'The medallion pattern organizes data in layers: bronze (raw ingested), silver (cleaned, conformed, joined), gold (business-level aggregates/marts). Each layer is a Delta table, improving quality and reusability progressively. It gives a clear, incremental, auditable pipeline structure.', followUp: 'What belongs in the gold layer?', checking: 'Lakehouse design pattern.', mistake: 'Dumping everything into one layer with no structure.' },
    { q: 'How do batch and streaming work together on Databricks?', short: 'Structured Streaming + Delta enables unified incremental batch and streaming.', strong: 'Spark Structured Streaming treats streams as incremental tables and writes to Delta with exactly-once guarantees; the same Delta tables serve batch queries. Auto Loader handles incremental file ingestion. This unifies batch and streaming code paths, simplifying pipelines that need both.', followUp: 'What does Auto Loader do?', checking: 'Streaming knowledge.', mistake: 'Maintaining separate, divergent batch and streaming codebases.' },
  ],
  'power-bi-interview-questions': [
    { q: 'What is the difference between DirectQuery and Import mode?', short: 'Import loads data into the model (fast); DirectQuery queries the source live (fresh).', strong: 'Import mode loads data into Power BI’s in-memory VertiPaq engine — fast and feature-rich but needs refresh and has size limits. DirectQuery queries the source at runtime — always current and handles huge data, but slower and with modeling limits. Composite models mix both. Choose by data size and freshness needs.', followUp: 'When would you accept DirectQuery’s slower performance?', checking: 'Modeling trade-off understanding.', mistake: 'Using Import for data too large or too real-time.' },
    { q: 'What is the difference between a calculated column and a measure?', short: 'Columns compute per row at refresh; measures compute at query time by context.', strong: 'A calculated column is evaluated row-by-row and stored in the model (uses memory), good for row-level attributes. A measure is evaluated at query time based on filter context and is not stored, ideal for aggregations. Prefer measures for calculations that respond to slicers/filters; overusing calculated columns bloats the model.', followUp: 'Why do measures respond to slicers but stored columns don’t recompute?', checking: 'DAX fundamentals.', mistake: 'Building aggregations as calculated columns.' },
    { q: 'Explain row context vs filter context in DAX.', short: 'Row context iterates rows; filter context is the set of filters applied to a calculation.', strong: 'Row context exists when iterating (calculated columns, iterators like SUMX) and refers to the current row. Filter context is the set of filters (from slicers, rows/columns, CALCULATE) restricting the data a measure sees. CALCULATE modifies filter context, and context transition converts row context to filter context. This is the crux of DAX.', followUp: 'What does CALCULATE do to filter context?', checking: 'Deep DAX understanding.', mistake: 'Confusing the two contexts and getting wrong totals.' },
    { q: 'How do you design an efficient Power BI data model?', short: 'Star schema with fact and dimension tables, not a flat or snowflaked mess.', strong: 'Model as a star schema: central fact tables (measures) linked to dimension tables (attributes) via single-direction relationships. Avoid overly wide flat tables and unnecessary bidirectional relationships. Reduce cardinality, hide keys, and use proper data types. A clean star schema drives both performance and correct DAX.', followUp: 'Why is a star schema better than one flat table?', checking: 'Modeling best practice.', mistake: 'Importing one huge denormalized table.' },
    { q: 'How do you optimize Power BI report performance?', short: 'Trim the model, prefer measures, reduce visuals/cardinality, and check the Performance Analyzer.', strong: 'Remove unused columns/tables, use Import where feasible, prefer measures over calculated columns, reduce visual count and high-cardinality slicers per page, and use aggregations for large models. Use the Performance Analyzer and DAX Studio to find slow visuals/queries. Model size and DAX are the usual bottlenecks.', followUp: 'What tool shows which visual is slow?', checking: 'Performance-tuning skill.', mistake: 'Blaming the service instead of profiling the model/DAX.' },
    { q: 'How do you implement row-level security (RLS)?', short: 'Define roles with DAX filters so users see only their data.', strong: 'RLS restricts data by user: define roles with DAX filter rules on tables (e.g., [Region] = USERPRINCIPALNAME() mapping), then assign users to roles in the service. Dynamic RLS uses a mapping table plus USERPRINCIPALNAME() to filter automatically. Test roles with "View as". It secures a shared report without separate copies.', followUp: 'How does dynamic RLS avoid a role per user?', checking: 'Security implementation.', mistake: 'Building separate reports per audience instead of using RLS.' },
  ],
  'qa-automation-interview-questions': [
    { q: 'How do you decide what to automate?', short: 'Automate stable, repetitive, high-value regression tests; not everything.', strong: 'Automate high-value, repetitive, stable scenarios — core regression, smoke, data-driven and cross-browser flows — where ROI is clear. Skip highly volatile UI, one-off exploratory checks, and things cheaper to test manually. Follow the test pyramid: many unit, fewer integration, fewest UI tests.', followUp: 'Why keep UI tests at the top (fewest) of the pyramid?', checking: 'Strategy over blind automation.', mistake: 'Automating everything through the slow, brittle UI layer.' },
    { q: 'What is the test automation pyramid?', short: 'Many fast unit tests, some integration tests, few end-to-end UI tests.', strong: 'The pyramid recommends a large base of fast, cheap unit tests, a middle layer of integration/API tests, and a small top of slow, brittle end-to-end UI tests. Inverting it (mostly UI tests) yields slow, flaky suites. Push coverage down to the lowest layer that can validate the behavior.', followUp: 'What’s the "ice-cream cone" anti-pattern?', checking: 'Test-strategy understanding.', mistake: 'Relying mostly on UI automation.' },
    { q: 'How do you design a maintainable automation framework?', short: 'Use Page Object Model, clear structure, reusable utilities and stable locators.', strong: 'Separate test logic from page interaction (Page Object Model or screenplay), centralize configuration and utilities, use stable locators, avoid hard waits, make tests independent and data-driven, and integrate with CI. Maintainability comes from good structure and no duplication, so UI changes touch one place.', followUp: 'How does POM reduce maintenance when the UI changes?', checking: 'Framework design.', mistake: 'Duplicating locators and logic across tests.' },
    { q: 'How do you handle flaky tests?', short: 'Fix root causes — waits, test data, isolation — rather than blind retries.', strong: 'Flakiness usually comes from timing (use explicit/auto waits, not sleeps), shared or dirty test data, order dependence, or environment instability. Diagnose with logs/traces/videos, isolate tests, control test data, and stabilize the environment. Retries can mask but shouldn’t replace fixing the cause.', followUp: 'Why are hard-coded sleeps a common cause of flakiness?', checking: 'Reliability engineering for tests.', mistake: 'Papering over flakiness with automatic retries only.' },
    { q: 'How do you integrate automation into CI/CD?', short: 'Run tests on every change, fast smoke first, full regression on schedule/pipeline gates.', strong: 'Trigger tests on commits/PRs: fast unit/smoke tests as gates, broader regression on merge or nightly. Run in parallel and in containers for consistency, publish reports and fail the pipeline on regressions. Keep the fast feedback loop tight so tests actually get run.', followUp: 'Why split smoke tests from full regression in CI?', checking: 'CI integration knowledge.', mistake: 'Running a huge slow suite on every commit, so people skip it.' },
    { q: 'How do you approach API test automation?', short: 'Test endpoints directly for speed and stability, covering contracts and edge cases.', strong: 'API tests hit endpoints directly (REST/GraphQL), validating status codes, schemas/contracts, data correctness, auth, and error/edge cases — faster and less brittle than UI tests. Use them to cover business logic, reserving UI tests for critical user journeys. Include contract testing between services.', followUp: 'Why are API tests less brittle than UI tests?', checking: 'Layered testing understanding.', mistake: 'Testing business logic only through the UI.' },
  ],
  'selenium-interview-questions': [
    { q: 'What are the different types of waits in Selenium?', short: 'Implicit, explicit and fluent waits; prefer explicit for reliability.', strong: 'Implicit wait sets a global polling timeout for element presence. Explicit wait (WebDriverWait + ExpectedConditions) waits for a specific condition on a specific element — the preferred, precise approach. Fluent wait adds custom polling/ignored exceptions. Avoid Thread.sleep and don’t mix implicit and explicit waits (unpredictable timeouts).', followUp: 'Why avoid mixing implicit and explicit waits?', checking: 'Reliability fundamentals.', mistake: 'Using Thread.sleep instead of explicit waits.' },
    { q: 'What locator strategies does Selenium support and which are best?', short: 'id/name/CSS/XPath/linkText; prefer stable id or CSS selectors.', strong: 'Selenium locates elements by id, name, className, tagName, linkText, CSS selector and XPath. Prefer stable, unique locators — ideally id or a good CSS selector; use XPath when you need traversal (parent/sibling) or text matching. Avoid brittle absolute XPaths and index-based locators.', followUp: 'When is XPath justified over CSS?', checking: 'Locator best practice.', mistake: 'Using long absolute XPaths that break on any DOM change.' },
    { q: 'What is the Page Object Model in Selenium?', short: 'A pattern encapsulating page elements and actions in classes.', strong: 'POM represents each page/component as a class holding its locators and interaction methods, separating test logic from UI details. When the UI changes, you update one page object rather than many tests. It improves readability, reuse and maintainability — the standard Selenium framework pattern.', followUp: 'How does POM reduce maintenance cost?', checking: 'Framework knowledge.', mistake: 'Scattering locators throughout test methods.' },
    { q: 'How do you handle dynamic elements and AJAX in Selenium?', short: 'Use explicit waits for the specific condition, with robust locators.', strong: 'For elements that load/change asynchronously, use explicit waits on conditions like visibility, clickability or presence, targeting stable attributes rather than volatile ones. Avoid fixed sleeps. For content loaded via AJAX, wait for the specific element/state you need before interacting.', followUp: 'What ExpectedCondition would you wait on before clicking?', checking: 'Handling real web apps.', mistake: 'Fixed sleeps that are either too short (flaky) or too long (slow).' },
    { q: 'How do you run Selenium tests across browsers and in parallel?', short: 'Use WebDriver for each browser and a grid/cloud plus a parallel-capable runner.', strong: 'Selenium supports multiple browsers via their drivers. For cross-browser and parallel execution, use Selenium Grid (or a cloud like BrowserStack) and a test runner/framework that runs threads/instances in parallel (TestNG, pytest-xdist). Ensure tests are independent and thread-safe (no shared driver state).', followUp: 'What must be true of tests to run them in parallel safely?', checking: 'Scaling test execution.', mistake: 'Sharing a single WebDriver instance across parallel tests.' },
    { q: 'What are common reasons Selenium tests are flaky?', short: 'Timing, unstable locators, test data and environment issues.', strong: 'Flakiness comes from improper waits (timing), brittle locators, order/data dependencies, and unstable environments. Fix with explicit waits, stable locators, independent tests with controlled data, and reliable environments. Capture screenshots/logs on failure to diagnose. Retries mask but don’t fix the cause.', followUp: 'How would you diagnose an intermittently failing test?', checking: 'Debugging skill.', mistake: 'Accepting flakiness as normal.' },
  ],
  'playwright-interview-questions': [
    { q: 'How does Playwright differ from Selenium?', short: 'Modern architecture with auto-waiting, multi-browser, and built-in tooling.', strong: 'Playwright drives browsers via the DevTools/CDP-style protocol with auto-waiting for elements to be actionable, reducing flakiness. It supports Chromium, Firefox and WebKit, offers powerful selectors, network interception, parallelism, tracing, and built-in test runner/fixtures out of the box — a more modern, batteries-included alternative to Selenium.', followUp: 'How does auto-waiting reduce flakiness?', checking: 'Modern E2E awareness.', mistake: 'Manually adding waits Playwright already handles.' },
    { q: 'What is auto-waiting and actionability in Playwright?', short: 'Playwright waits for elements to be visible, stable and enabled before acting.', strong: 'Before clicking/typing, Playwright automatically waits for the element to be attached, visible, stable (not animating), enabled and to receive events — so you rarely need explicit waits. This "actionability" model removes most timing flakiness that plagues older tools.', followUp: 'What actionability checks run before a click?', checking: 'Core Playwright concept.', mistake: 'Adding manual sleeps that fight auto-waiting.' },
    { q: 'What are Playwright fixtures and why use them?', short: 'Built-in test fixtures provide isolated context/page and reusable setup.', strong: 'Playwright Test fixtures (page, context, browser, and custom ones) provide isolated, per-test setup/teardown — each test gets a fresh browser context, avoiding shared state. Custom fixtures encapsulate reusable setup (auth, data), keeping tests clean and parallel-safe. This isolation is key to reliable, parallel runs.', followUp: 'Why does each test getting a fresh context help?', checking: 'Framework understanding.', mistake: 'Sharing state across tests and causing interference.' },
    { q: 'How does Playwright handle network interception and mocking?', short: 'route() intercepts requests to mock, modify or block responses.', strong: 'page.route() intercepts network requests so you can mock API responses, modify payloads, block resources, or simulate errors and slow networks — enabling fast, deterministic tests independent of backends and testing of edge cases. Great for isolating the frontend under test.', followUp: 'Why mock APIs in E2E tests sometimes?', checking: 'Advanced testing capability.', mistake: 'Depending on live backends for every UI test, causing flakiness.' },
    { q: 'How do you debug failing Playwright tests?', short: 'Use trace viewer, screenshots, videos, and headed/debug mode.', strong: 'Playwright records traces (DOM snapshots, network, console) you open in the Trace Viewer to see exactly what happened, plus screenshots and videos on failure. Run headed or with the inspector (PWDEBUG) to step through. This rich tooling makes diagnosing failures far faster than log-only debugging.', followUp: 'What does the Trace Viewer show you?', checking: 'Debugging proficiency.', mistake: 'Debugging with print statements when tracing is built in.' },
    { q: 'How do you structure and scale a Playwright test suite?', short: 'Use projects for browsers, POM for structure, and built-in parallelism.', strong: 'Use Playwright projects to run across browsers/devices, organize with the Page Object Model or component helpers, share setup via fixtures, and rely on built-in parallel workers for speed. Integrate with CI, use test tags/sharding for large suites, and keep tests independent. It scales without extra grid infrastructure.', followUp: 'How does Playwright parallelize without a separate grid?', checking: 'Scaling modern E2E.', mistake: 'Writing serial, interdependent tests that can’t parallelize.' },
  ],
  'workday-interview-questions': [
    { q: 'What is a business process in Workday and why is it central?', short: 'A configurable sequence of steps (actions, approvals, conditions) that drives transactions.', strong: 'A Business Process (BP) is Workday’s configurable workflow — a sequence of steps like initiation, approvals, to-dos, conditions and notifications — that governs transactions (hire, change job, etc.). Almost everything in Workday runs through BPs, and security and routing attach to them, so understanding BP configuration is core to Workday work.', followUp: 'How does security interact with business process steps?', checking: 'Core Workday concept.', mistake: 'Treating Workday like a static form app rather than BP-driven.' },
    { q: 'Explain Workday security: domain vs business process security.', short: 'Domain security controls data/task access; BP security controls who can act on process steps.', strong: 'Domain security policies grant view/modify access to data and tasks grouped into functional domains. Business process security policies control who can initiate, approve or act on BP steps. Both are assigned to security groups, and changes require activating pending security. Getting this right is critical and a frequent interview focus.', followUp: 'What must you do after editing a security policy?', checking: 'Security model understanding.', mistake: 'Forgetting to activate pending security changes.' },
    { q: 'What are the main types of Workday reports?', short: 'Standard (delivered), custom (Advanced, Matrix, Composite, Trending) built in the report writer.', strong: 'Workday has delivered standard reports and custom reports built in the report writer: Simple, Advanced (most common, supports prompts/sharing/exposing as web service), Matrix (aggregations), Composite (financial-style), and Trending. Choosing the right type and data source (with the correct business object) is key to reporting.', followUp: 'Which report type would you expose as a web service for integration?', checking: 'Reporting knowledge.', mistake: 'Using the wrong report type or data source.' },
    { q: 'What are calculated fields and where are they used?', short: 'Reusable fields that derive values, used in reports, integrations and conditions.', strong: 'Calculated fields derive new values from existing data using functions (lookup, arithmetic, date, text, evaluate expression) and are reusable across reports, integrations, business process conditions and condition rules. They are powerful but can impact performance, so build them efficiently and reuse rather than duplicate.', followUp: 'Why can complex calculated fields hurt report performance?', checking: 'Practical configuration skill.', mistake: 'Overusing heavy calculated fields and duplicating logic.' },
    { q: 'How does Workday handle configuration vs customization?', short: 'Workday is configured (no custom code); updates are seamless because you don’t modify core code.', strong: 'Workday is configured through tenant setup — business processes, security, reports, calculated fields, EIB/integrations — not custom-coded like on-prem ERPs. This is why twice-yearly updates apply without breaking customizations. "Customization" in Workday means configuration and integrations, so upgrade impact is much lower.', followUp: 'Why do Workday’s two annual updates rarely break tenants?', checking: 'Platform philosophy.', mistake: 'Expecting code-level customization like legacy ERPs.' },
    { q: 'How are integrations built in Workday?', short: 'EIB for simple, Core Connectors for packaged, and Studio for complex integrations.', strong: 'EIB (Enterprise Interface Builder) handles simple inbound/outbound data via templates. Core Connectors are pre-built for common integrations (payroll, benefits). Workday Studio builds complex, custom integrations with transformations. All leverage Workday web services (SOAP/REST) and reports-as-a-service. Choose by complexity.', followUp: 'When would you move from EIB to Studio?', checking: 'Integration approach.', mistake: 'Forcing complex logic into an EIB that needs Studio.' },
  ],
  'workday-hcm-interview-questions': [
    { q: 'Explain the Workday HCM organizational structure (supervisory orgs, etc.).', short: 'Supervisory organizations form the backbone; other org types layer on roles and reporting.', strong: 'Supervisory organizations define reporting hierarchy and are the backbone HCM structure to which workers and positions attach. Other organization types (cost center, company, location, matrix, custom) layer financial, geographic and reporting dimensions. Understanding how workers, positions and orgs relate is fundamental to HCM configuration.', followUp: 'What happens to workers when a supervisory org is reorganized?', checking: 'Core HCM structure.', mistake: 'Confusing supervisory orgs with other org types.' },
    { q: 'What is the difference between position management and job management?', short: 'Position management pre-defines positions; job management is looser, headcount-based.', strong: 'Position Management creates and controls specific positions (approved, budgeted seats) that workers fill — tighter control, common in large/regulated orgs. Job Management manages staffing more loosely by job without pre-defined positions — simpler, flexible. The staffing model is set per supervisory org and shapes hiring processes.', followUp: 'Which model suits a headcount-controlled enterprise?', checking: 'Staffing model understanding.', mistake: 'Mixing up the two staffing models.' },
    { q: 'How do compensation and job profiles work in Workday HCM?', short: 'Job profiles define role attributes; compensation is delivered via grades, plans and packages.', strong: 'Job profiles define the reusable attributes of a role (skills, qualifications, pay-rate type, job family). Compensation uses grades/grade profiles, compensation plans (salary, bonus, allowance) and eligibility rules to build packages assigned to workers. Understanding how profiles, positions and comp link is core to HCM.', followUp: 'How does a job profile relate to a position?', checking: 'HCM configuration depth.', mistake: 'Confusing job profile, job family and position.' },
    { q: 'What are the key hire/staffing business processes?', short: 'Hire, Add Job, Change Job, Termination — each a configurable BP with steps and security.', strong: 'Core staffing BPs include Hire, Add Additional Job, Change Job (transfers, promotions), and Termination/End Additional Job. Each is a configurable business process with initiation, approvals, sub-processes and notifications, governed by BP security. Knowing their steps and downstream effects (comp, org, security) is essential.', followUp: 'What downstream events does a Change Job trigger?', checking: 'Process knowledge.', mistake: 'Not understanding sub-processes triggered by staffing events.' },
    { q: 'How is worker data secured in Workday HCM?', short: 'Role-based and user-based security groups plus domain/BP policies control access.', strong: 'Access is granted via security groups (role-based tied to org roles, user-based, job-based, etc.) mapped to domain security policies (data) and business process security policies (actions). Sensitive HCM data (comp, personal) is tightly scoped. Configuring least-privilege access and testing with "View As" is standard.', followUp: 'How would you give managers access only to their own team’s data?', checking: 'Security application in HCM.', mistake: 'Over-granting access to sensitive worker data.' },
    { q: 'What are EIBs commonly used for in HCM?', short: 'Bulk loading/updating worker data and simple outbound extracts.', strong: 'EIBs are widely used in HCM for mass data loads (e.g., loading workers, comp changes, org updates during implementation) and simple outbound extracts to downstream systems. They use spreadsheet templates mapped to Workday web services. For repeatable or complex flows, Core Connectors/Studio are used instead.', followUp: 'When is an EIB the wrong tool for an HCM integration?', checking: 'Practical HCM integration.', mistake: 'Using EIB for complex, transformation-heavy integrations.' },
  ],
  'workday-integration-interview-questions': [
    { q: 'Compare EIB, Core Connectors and Workday Studio.', short: 'EIB = simple, Core Connectors = packaged, Studio = complex custom integrations.', strong: 'EIB handles simple inbound/outbound integrations via templates and basic transformations. Core Connectors are Workday-delivered, configurable integrations for common domains (payroll, benefits) with Connector transformations. Studio is an Eclipse-based IDE for complex, multi-step custom integrations with rich transformation and orchestration. Choose by complexity and reuse.', followUp: 'What can Studio do that an EIB cannot?', checking: 'Integration tool selection.', mistake: 'Defaulting to Studio for what an EIB handles, or vice versa.' },
    { q: 'How does Workday expose data for integrations?', short: 'Web services (SOAP/REST) and Report-as-a-Service (RaaS).', strong: 'Workday exposes public web service APIs (SOAP, plus growing REST) per functional area, and any Advanced report can be exposed as a web service (RaaS) to deliver custom data sets. Integrations consume these with proper ISU/ISSG security. RaaS is a common, flexible way to get exactly the data you need.', followUp: 'What is RaaS and when do you use it?', checking: 'Data-access knowledge.', mistake: 'Building custom code when a RaaS report would suffice.' },
    { q: 'What are ISU and ISSG, and why do they matter?', short: 'Integration System User and Integration System Security Group secure integrations.', strong: 'An Integration System User (ISU) is a dedicated account that runs integrations; an Integration System Security Group (ISSG) grants that ISU the specific domain/BP permissions it needs. Using a scoped ISU/ISSG (least privilege, often with password never-expires and restricted to integration) is the secure standard for integrations.', followUp: 'Why not run integrations under a normal user account?', checking: 'Integration security.', mistake: 'Over-permissioning the ISU or using a personal account.' },
    { q: 'How do transformations work in Workday integrations?', short: 'XSLT/ETV and Studio transformations convert Workday XML to the target format.', strong: 'Integrations transform Workday’s XML output to the target format using XSLT, Enterprise Transformation (document transformation), or Studio’s components. You map fields, apply logic, and produce the file/format the downstream system expects. Solid XML/XSLT and understanding of Workday’s data structures are key skills.', followUp: 'What skill underpins most Workday transformations?', checking: 'Technical integration depth.', mistake: 'Weak XML/XSLT knowledge for transformation-heavy work.' },
    { q: 'How do you schedule and monitor integrations?', short: 'Schedule via BP/process scheduler; monitor with integration events and error handling.', strong: 'Integrations run on schedules (integration schedules/process framework) or on demand. You monitor via the integration event, which shows status, output, and errors, and configure notifications and retry/alerting. Good error handling and reviewing integration events are essential for reliable operations.', followUp: 'Where do you look to debug a failed integration run?', checking: 'Operational integration knowledge.', mistake: 'No monitoring or error alerting on scheduled integrations.' },
    { q: 'How do you secure and handle sensitive data in integrations?', short: 'Least-privilege ISU, encryption (PGP), and secure transport (SFTP).', strong: 'Scope the ISU/ISSG to only needed domains, encrypt sensitive output (PGP) and use secure transport (SFTP with keys), and avoid exposing more data than required in the RaaS/report. Audit and rotate credentials. Payroll and PII integrations especially demand encryption and tight access.', followUp: 'How would you protect a payroll extract in transit?', checking: 'Secure integration practice.', mistake: 'Sending sensitive data unencrypted or over insecure channels.' },
  ],
  'workday-security-interview-questions': [
    { q: 'What are the main types of security groups in Workday?', short: 'Role-based, user-based, job-based, and others, each granting access differently.', strong: 'Common types include role-based (tied to an org role, e.g., Manager for their org), user-based (explicit members), job-based, location membership, and intersection/aggregation groups. Choosing the right type controls how access scopes to data — role-based for contextual access, user-based for fixed sets. Getting this right prevents over- or under-access.', followUp: 'When would you use an intersection security group?', checking: 'Security-group design.', mistake: 'Using user-based groups where role-based contextual access is needed.' },
    { q: 'How do domain security policies work?', short: 'They grant view/modify access to grouped data and tasks per security group.', strong: 'A domain groups related securable items (data, reports, tasks). A domain security policy grants specific security groups view and/or modify access to that domain. To take effect, edited policies must be activated (activate pending security changes). Least-privilege domain configuration is central to Workday security.', followUp: 'What’s the difference between view and modify access?', checking: 'Domain-security depth.', mistake: 'Forgetting to activate pending security changes.' },
    { q: 'How does business process security work?', short: 'BP security policies control who can initiate and act on each process step.', strong: 'Each business process type has a security policy defining which security groups can initiate it and act on each step (approve, review, etc.). This is separate from domain (data) security — a user may see data but not be able to approve a step, or vice versa. Aligning both is essential for correct workflows.', followUp: 'Can a user view data but be unable to approve the related BP step?', checking: 'BP-security understanding.', mistake: 'Confusing data access with the ability to act on a process.' },
    { q: 'What is the purpose of the "View Security for Securable Item" / security analysis tools?', short: 'They show who has access to an item and why, for auditing and troubleshooting.', strong: 'Workday provides tools to analyze security — viewing which security groups/users can access a securable item and through which policies, and "View As" to test a user’s experience. These are essential for auditing least privilege, troubleshooting "why can/can’t this user see X", and validating changes before activation.', followUp: 'How do you verify a change gives exactly the intended access?', checking: 'Auditing skill.', mistake: 'Changing security without testing the actual effective access.' },
    { q: 'How do you implement least privilege in Workday?', short: 'Grant minimal domain/BP access via appropriately scoped security groups; review regularly.', strong: 'Assign users to role-based groups scoped to their org context, grant only the domains and BP steps they need (view vs modify), avoid broad user-based admin groups, and review access periodically. Test with security analysis and "View As". Least privilege limits exposure of sensitive HR/finance data.', followUp: 'How would you audit for over-permissioned users?', checking: 'Security best practice.', mistake: 'Broad access "to be safe", exposing sensitive data.' },
    { q: 'What happens during a security change and activation?', short: 'Edits are pending until you activate pending security changes, which applies them.', strong: 'Security policy edits don’t take effect immediately — they’re staged as pending changes. You must "Activate Pending Security Policy Changes" (with a comment) to apply them tenant-wide. This lets you review multiple changes before committing. Forgetting to activate is a classic reason "my change didn’t work".', followUp: 'Why does Workday stage security changes before activation?', checking: 'Operational security knowledge.', mistake: 'Assuming edits apply instantly without activation.' },
  ],
  'uipath-interview-questions': [
    { q: 'What is the UiPath platform architecture (Studio, Robot, Orchestrator)?', short: 'Studio builds automations, Robots run them, Orchestrator manages and schedules.', strong: 'UiPath Studio is the IDE for designing workflows; Robots (attended/unattended) execute them on machines; Orchestrator is the central server for deploying, scheduling, monitoring, queue management and credential storage. This separation lets you build once and manage/scale execution centrally.', followUp: 'What is the difference between attended and unattended robots?', checking: 'Platform fundamentals.', mistake: 'Confusing the roles of Studio, Robot and Orchestrator.' },
    { q: 'What is the REFramework and why use it?', short: 'A robust enterprise template with state machine, config, logging and exception handling.', strong: 'The Robotic Enterprise Framework is UiPath’s template built on a state machine (Init, Get Transaction, Process, End) with centralized configuration, queue-based transactions, retry logic, robust exception handling and logging. It provides a reliable, maintainable foundation for production automations instead of ad-hoc sequences.', followUp: 'What are the states in the REFramework?', checking: 'Enterprise automation practice.', mistake: 'Building production bots as fragile linear sequences.' },
    { q: 'How do you handle exceptions in UiPath?', short: 'Distinguish business vs application exceptions; use Try-Catch, retries and logging.', strong: 'Application/system exceptions (element not found, app crash) are typically retried; business exceptions (invalid data per rules) are logged and skipped, not retried. Use Try-Catch, the REFramework’s exception handling, retry scopes, screenshots and clear logging. Correctly categorizing exceptions is key to reliable automation.', followUp: 'Why retry application exceptions but not business exceptions?', checking: 'Robust bot design.', mistake: 'Treating all exceptions the same and retrying business errors.' },
    { q: 'What are queues in Orchestrator and when do you use them?', short: 'Queues hold transaction items for scalable, resilient, distributed processing.', strong: 'Orchestrator queues store transaction items that robots process one by one, enabling load distribution across multiple robots, automatic retries, status tracking and resilience (work isn’t lost if a bot fails). They’re central to the REFramework’s transactional model for high-volume, reliable automation.', followUp: 'How do queues enable multiple robots to share work?', checking: 'Scalable automation design.', mistake: 'Processing high volumes without queues, losing resilience.' },
    { q: 'What are selectors and how do you make them reliable?', short: 'XML fragments identifying UI elements; use stable attributes and dynamic selectors.', strong: 'Selectors identify UI elements via attributes. Reliable automation uses stable, unique attributes, avoids volatile ones (indexes, dynamic IDs), and uses wildcards/variables for dynamic parts. Anchors and UI frameworks (UIAutomation) help. Fragile selectors are the top cause of bot breakage.', followUp: 'How do you handle a selector attribute that changes each run?', checking: 'Practical automation reliability.', mistake: 'Relying on brittle, index-based selectors.' },
    { q: 'How do you manage credentials and configuration securely?', short: 'Store credentials in Orchestrator assets/credential stores; config in assets/config file.', strong: 'Keep credentials in Orchestrator credential assets or an integrated credential store (never hardcoded), and keep environment-specific settings in Orchestrator assets or the REFramework config file so bots move between environments cleanly. This secures secrets and makes automations maintainable.', followUp: 'Why never hardcode passwords in a workflow?', checking: 'Security and maintainability.', mistake: 'Hardcoding credentials or config in the workflow.' },
  ],
  'rpa-interview-questions': [
    { q: 'What is RPA and what processes are good candidates for it?', short: 'Software bots automating rule-based, repetitive, high-volume digital tasks.', strong: 'RPA uses software robots to mimic human actions across applications for rule-based, repetitive, high-volume, stable processes with structured input (data entry, reconciliation, report generation). Good candidates are well-defined and standardized; poor candidates are highly variable, judgment-heavy or frequently-changing processes.', followUp: 'What makes a process a poor RPA candidate?', checking: 'Automation suitability judgment.', mistake: 'Automating unstable or judgment-heavy processes.' },
    { q: 'How do you approach exception handling and resilience in RPA?', short: 'Categorize business vs system exceptions, retry appropriately, log and alert.', strong: 'Design bots to distinguish business exceptions (data/rule violations — log and skip) from system exceptions (app/environment issues — retry, then escalate), with try-catch, retry logic, screenshots and detailed logging. Resilient bots recover gracefully and don’t lose transactions — often via a queue-based transactional model.', followUp: 'How do queues improve bot resilience?', checking: 'Reliable automation design.', mistake: 'No exception strategy, so one failure stops everything.' },
    { q: 'What is the difference between attended and unattended automation?', short: 'Attended runs with a human on their machine; unattended runs autonomously, usually scheduled.', strong: 'Attended bots assist a human at their desktop, triggered by the user for front-office tasks. Unattended bots run without human interaction, typically scheduled/triggered on servers for back-office, high-volume processing, managed centrally. Many solutions combine both. The choice shapes infrastructure and licensing.', followUp: 'Which suits high-volume overnight batch processing?', checking: 'Deployment-model understanding.', mistake: 'Confusing the two models and their use cases.' },
    { q: 'How do you calculate ROI and prioritize RPA opportunities?', short: 'Weigh volume, time saved, error reduction and stability against build/maintenance cost.', strong: 'Estimate benefit (hours saved × volume, error/quality gains, compliance) versus cost (development, licensing, maintenance) and feasibility (process stability, structured data). Prioritize high-volume, stable, high-effort processes. A process that changes often has high maintenance cost that can erase ROI.', followUp: 'Why does process volatility hurt RPA ROI?', checking: 'Business-value thinking.', mistake: 'Automating low-volume or unstable processes with poor ROI.' },
    { q: 'How do you handle changes to underlying applications that break bots?', short: 'Robust selectors, monitoring, a governance/maintenance process and change awareness.', strong: 'UI changes are the top cause of bot failure. Mitigate with resilient selectors/anchors, monitoring and alerting on failures, a maintenance/support model, and coordination with app teams about upcoming changes. Treat bots as software needing versioning, testing and ongoing maintenance — not fire-and-forget.', followUp: 'Why treat bots as maintained software?', checking: 'Operational RPA maturity.', mistake: 'Deploying bots with no maintenance plan.' },
    { q: 'Where does intelligent automation / AI fit with RPA?', short: 'AI (OCR, ML, GenAI) extends RPA to unstructured data and decisions.', strong: 'RPA handles structured, rule-based steps; adding AI — document understanding/OCR, ML classification, and increasingly GenAI/LLMs — lets automations process unstructured inputs (invoices, emails) and make judgment-based decisions. This "intelligent automation" expands what can be automated beyond deterministic rules.', followUp: 'What kind of task needs AI on top of plain RPA?', checking: 'Awareness of the 2026 automation direction.', mistake: 'Assuming RPA alone handles unstructured documents well.' },
  ],
  'salesforce-interview-questions': [
    { q: 'When should you use configuration (clicks) vs code (Apex) in Salesforce?', short: 'Prefer declarative tools; use Apex only when config can’t meet the requirement.', strong: 'Salesforce best practice is "clicks before code": use declarative tools (Flow, validation rules, formula fields, automation) first because they’re easier to maintain and upgrade-safe. Use Apex/LWC when logic exceeds declarative limits (complex transactions, bulk logic, callouts, advanced UI). Overusing code adds maintenance burden.', followUp: 'What can Flow do that used to require Apex?', checking: 'Platform philosophy.', mistake: 'Writing Apex for what Flow/config can handle.' },
    { q: 'What are Salesforce governor limits and why do they exist?', short: 'Per-transaction limits (SOQL, DML, CPU) enforcing multi-tenant fairness.', strong: 'Because Salesforce is multi-tenant, governor limits cap per-transaction resource use — SOQL queries (100), DML statements (150), CPU time, heap, etc. — so no tenant monopolizes shared resources. Code must be bulkified (handle collections, no queries/DML in loops) to stay within limits. Hitting limits is a top cause of failures.', followUp: 'How does bulkification keep you within limits?', checking: 'Core platform constraint.', mistake: 'Putting SOQL/DML inside loops and blowing limits.' },
    { q: 'What does it mean to write bulkified Apex?', short: 'Handle many records at once — no SOQL/DML inside loops.', strong: 'Bulkified Apex processes collections of records efficiently: query once for all needed data, operate in memory, and perform DML on lists outside loops. Triggers must handle batches (up to 200 records) because Salesforce invokes them in bulk. Non-bulkified code fails as soon as volume rises. It’s the number-one Apix best practice.', followUp: 'Why do triggers need to handle 200 records at once?', checking: 'Apex best practice.', mistake: 'Writing per-record logic that queries inside loops.' },
    { q: 'Explain Apex triggers and best practices.', short: 'Before/after DML logic; use one trigger per object with a handler and bulk-safe logic.', strong: 'Triggers run on DML events (before/after insert/update/delete). Best practices: one trigger per object delegating to a handler class, bulk-safe logic (no SOQL/DML in loops), avoid recursion (static flags), keep logic out of the trigger body, and respect order of execution. This keeps automation predictable and maintainable.', followUp: 'Why one trigger per object rather than many?', checking: 'Apex architecture.', mistake: 'Multiple triggers per object with logic in the trigger body.' },
    { q: 'What are Lightning Web Components (LWC)?', short: 'Modern, standards-based web components for building Salesforce UI.', strong: 'LWC is Salesforce’s modern UI framework built on web-standards (custom elements, shadow DOM, modern JS), replacing much of Aura. It’s performant and interoperable, communicates with Apex/wire services for data, and follows a component model. Knowing LWC (and when to use it vs Flow/config) is expected for developer roles.', followUp: 'How does an LWC get data from Salesforce?', checking: 'Modern SF development.', mistake: 'Only knowing legacy Visualforce/Aura.' },
    { q: 'How do you secure data in Salesforce (sharing model)?', short: 'Org-wide defaults, roles, sharing rules, profiles/permission sets, and field-level security.', strong: 'Salesforce security layers: object/field access via profiles and permission sets, and record access via org-wide defaults (baseline), role hierarchy, sharing rules and manual/Apex sharing. FLS controls fields. Understanding how these combine (most permissive record access wins within the sharing model) is essential and a common interview topic.', followUp: 'What’s the difference between a profile and a sharing rule?', checking: 'Security model depth.', mistake: 'Confusing object/field permissions with record-level sharing.' },
  ],
  'sap-interview-questions': [
    { q: 'What is the difference between SAP ECC and S/4HANA?', short: 'S/4HANA is the modern suite on the HANA in-memory DB with a simplified data model.', strong: 'ECC is the older ERP running on traditional databases; S/4HANA runs exclusively on the HANA in-memory database with a simplified data model (e.g., Universal Journal in Finance), real-time analytics, and Fiori UX. Migrations (greenfield/brownfield) to S/4HANA are a major 2026 focus as ECC approaches end of mainstream support.', followUp: 'What does the HANA in-memory DB enable that traditional DBs did not?', checking: 'Current SAP landscape.', mistake: 'Being unaware of the ECC → S/4HANA shift.' },
    { q: 'What are SAP modules and how do they integrate?', short: 'Functional modules (FI, CO, MM, SD, PP, HR) share a common data model and integrate in real time.', strong: 'SAP is organized into functional modules — Finance (FI), Controlling (CO), Materials Management (MM), Sales & Distribution (SD), Production Planning (PP), HR, etc. — that integrate tightly: e.g., a goods movement in MM posts to FI automatically. Understanding cross-module integration (order-to-cash, procure-to-pay) is key for functional roles.', followUp: 'Trace how a sales order (SD) impacts FI and MM.', checking: 'Cross-module process understanding.', mistake: 'Viewing modules in isolation.' },
    { q: 'What is a transport in SAP and why is it important?', short: 'A packaged change moved through the landscape (DEV → QA → PROD).', strong: 'Transports carry configuration and development objects through the system landscape (Development → Quality → Production) via the Transport Management System, ensuring changes are tested before production and applied consistently. Understanding transport sequence and dependencies prevents broken production moves — a common practical topic.', followUp: 'What happens if transports are imported out of sequence?', checking: 'Change-management knowledge.', mistake: 'Ignoring transport order and dependencies.' },
    { q: 'What is ABAP and where is it used?', short: 'SAP’s programming language for custom reports, enhancements and interfaces.', strong: 'ABAP is SAP’s proprietary language for custom development — reports, interfaces, conversions, enhancements, forms (RICEF) — and increasingly modern ABAP (with CDS views, RAP) on S/4HANA. Even config-heavy roles benefit from understanding how custom code and standard SAP interact, and the push toward "clean core" (minimizing modifications).', followUp: 'What does "keep the core clean" mean in S/4HANA?', checking: 'Technical/functional awareness.', mistake: 'Heavy core modifications that complicate upgrades.' },
    { q: 'What are common SAP integration technologies?', short: 'IDocs, BAPIs/RFCs, OData/APIs, and middleware like SAP PI/PO or Integration Suite.', strong: 'SAP integrates via IDocs (structured document messages), BAPIs/RFCs (function-based), and modern OData/REST APIs, often orchestrated through middleware (SAP PI/PO, Cloud Integration/Integration Suite). S/4HANA and cloud push toward API-first, OData and event-driven integration. Choosing the right mechanism depends on the systems and real-time needs.', followUp: 'When would you use an IDoc vs an OData API?', checking: 'Integration knowledge.', mistake: 'Assuming one integration method fits all cases.' },
    { q: 'What is SAP Fiori and why does it matter?', short: 'SAP’s modern, role-based, responsive UX replacing classic SAP GUI screens.', strong: 'Fiori is SAP’s modern user experience — role-based, responsive apps built on UI5/OData that replace transaction-code-heavy SAP GUI screens, central to S/4HANA. It improves usability and adoption. Knowing Fiori app types (transactional, analytical, fact sheets) and the launchpad is increasingly expected.', followUp: 'How does Fiori differ from the classic SAP GUI?', checking: 'Modern SAP UX awareness.', mistake: 'Assuming SAP is still only green-screen transactions.' },
  ],
};
